const deepClone=v=>JSON.parse(JSON.stringify(v));
const avg=a=>a.length?a.reduce((s,n)=>s+Number(n||0),0)/a.length:0;

const ROLE_DEFINITIONS=window.ValoraRoles?.ROLE_DEFINITIONS||{};
