const GLOBAL_ROLES=window.ValoraRoles?.GLOBAL_ROLES||['admin_valora','consultor_valora'];
const COMPANY_ROLES=window.ValoraRoles?.COMPANY_ROLES||['empresa_admin','gestor_pesquisa','analista_resultados','gestor_area','participante','convidado_externo'];
function getRoleDefinition(role){return window.ValoraRoles?.getRoleDefinition(role)||ROLE_DEFINITIONS[role]||{label:role||'Sem perfil',description:'Perfil não reconhecido.',scope:'unknown'};}
function can(user,permission){return window.ValoraRoles?.can(user,permission)??!!(user&&getRoleDefinition(user.role)[permission]);}
function canAccessCompany(user,companyId){return window.ValoraRoles?.canAccessCompany(user,companyId)??(!!user&&(GLOBAL_ROLES.includes(user.role)||user.companyId===companyId));}
function canCreateUserWithRole(current,targetRole){return window.ValoraRoles?.canCreateRole(current,targetRole)??false;}
function availableRolesForCurrentUser(current){return window.ValoraRoles?.availableRolesForCurrentUser(current)||Object.keys(ROLE_DEFINITIONS).filter(r=>canCreateUserWithRole(current,r));}
function availableRolesForCompanyUser(current){return window.ValoraRoles?.availableCompanyRolesFor(current)||availableRolesForCurrentUser(current).filter(r=>COMPANY_ROLES.includes(r));}
function roleHint(role){const d=getRoleDefinition(role);return `<div class="page-help role-help"><b>${esc(d.label)}:</b> ${esc(d.description)}</div>`;}
