function renderSignup(){ $('#app').innerHTML=`<section class="auth-shell"><div class="auth-card"><span class="badge">Plano Gratuito padrão</span><h1 class="section-title">Criar ambiente</h1><p class="section-lead">Cadastre uma empresa ou pessoa física. Para CNPJ e CEP, use as buscas integradas.</p><form class="grid" data-form="signup"><div class="form-grid"><div class="field"><label>Tipo</label><select name="type"><option value="juridica">Empresa / CNPJ</option><option value="fisica">Pessoa física</option></select></div><div class="field"><label>Plano</label><select name="planId">${state.plans.map(p=>`<option value="${p.id}" ${p.default?'selected':''}>${esc(p.name)} — ${p.price?money(p.price)+'/mês':'Grátis'}</option>`).join('')}</select></div><div class="field"><label>CNPJ ou CPF</label><div class="inline-field"><input name="document"><button type="button" class="btn btn-soft btn-mini" data-action="lookupCnpj">Buscar CNPJ</button></div></div><div class="field"><label>Empresa ou nome</label><input name="companyName" required></div><div class="field"><label>Nome do gestor</label><input name="name" required></div><div class="field"><label>E-mail</label><input name="email" type="email" required></div><div class="field"><label>Telefone</label><input name="phone"></div><div class="field"><label>CEP</label><div class="inline-field"><input name="cep"><button type="button" class="btn btn-soft btn-mini" data-action="lookupCep">Buscar CEP</button></div></div><div class="field span-2"><label>Endereço</label><input name="address"></div><div class="field"><label>Senha</label><input name="password" type="password" minlength="6" required></div><div class="field"><label>Confirmar senha</label><input name="password2" type="password" minlength="6" required></div></div><details class="legal-box"><summary>Ler o termo LGPD</summary><div>${nl2br((state.settings.lgpdText||LGPD_TEXT).slice(0,2500))}</div></details><label class="checkline"><input name="lgpd" type="checkbox" required><span>Li e aceito o tratamento dos dados para criação e administração do ambiente.</span></label><button class="btn btn-primary btn-block">Criar ambiente</button></form></div></section>`; }
