function renderPortal(scope,tab){
  const user=currentUser();if(!user)return renderLogin('Entre para acessar sua área.');
  const menu=menuFor(scope);const selected=menu.some(x=>x.id===tab&&!x.disabled)?tab:(menu.find(x=>!x.disabled)?.id||'dashboard');
  $('#app').innerHTML=`<div class="app-shell"><aside class="sidebar"><div class="who"><b>${esc(user.name)}</b><span>${esc(ROLE_LABELS[user.role]||user.role)}</span><span>${esc(user.companyId?companyName(user.companyId):'Valora Group')}</span></div><nav class="side-menu" aria-label="Menu da área">${menu.map(x=>`<button class="${x.id===selected?'active':''}" data-action="portalTab" data-scope="${scope}" data-tab="${x.id}" ${x.disabled?'disabled':''}>${esc(x.label)}</button>`).join('')}</nav></aside><section class="content" id="portalContent"></section></div>`;
  renderPortalTab(scope,selected);
}
function menuFor(scope){
  const user=currentUser(),role=user?.role;
  if(scope==='participante')return role==='convidado_externo'?[]:[{id:'dashboard',label:'Minha área'},{id:'available',label:'Pesquisas disponíveis'},{id:'responses',label:'Pesquisas respondidas'},{id:'certificates',label:'Certificados'},{id:'privacy',label:'Privacidade e LGPD'}];
  if(scope==='empresa'){
    if(role==='gestor_area')return [{id:'dashboard',label:'Visão geral da área'},{id:'responses',label:'Respostas da área'},{id:'actionPlans',label:'Plano de ação',disabled:!moduleEnabled('actionPlans')},{id:'reports',label:'Relatórios da área',disabled:!moduleEnabled('relatorios')}];
    if(role==='analista_resultados')return [{id:'dashboard',label:'Visão geral'},{id:'responses',label:'Respostas'},{id:'actionPlans',label:'Plano de ação',disabled:!moduleEnabled('actionPlans')},{id:'reports',label:'Relatórios',disabled:!moduleEnabled('relatorios')}];
    const items=[{id:'dashboard',label:'Visão geral'}];
    if(can(user,'canCreateSurveys'))items.push({id:'surveys',label:'Pesquisas',disabled:!moduleEnabled('pesquisas')});
    if(can(user,'canCreateForms'))items.push({id:'forms',label:'Formulários',disabled:!moduleEnabled('formularios')});
    if(can(user,'canSendInvites'))items.push({id:'users',label:'Funcionários'});
    if(can(user,'canViewResponses'))items.push({id:'responses',label:'Respostas'});
    if(can(user,'canViewReports'))items.push({id:'actionPlans',label:'Plano de ação',disabled:!moduleEnabled('actionPlans')});
    if(can(user,'canViewReports'))items.push({id:'reports',label:'Relatórios',disabled:!moduleEnabled('relatorios')});
    if(can(user,'canViewPlan'))items.push({id:'plan',label:'Plano contratado'});
    if(can(user,'canEditOwnCompany'))items.push({id:'settings',label:'Dados da empresa'});
    return items;
  }
  if(role==='consultor_valora')return [{id:'dashboard',label:'Dashboard'},{id:'clients',label:'Clientes'},{id:'surveys',label:'Pesquisas'},{id:'forms',label:'Formulários'},{id:'responses',label:'Respostas'},{id:'reports',label:'Relatórios'},{id:'actionPlans',label:'Plano de ação'}];
  return [{id:'dashboard',label:'Dashboard'},{id:'clients',label:'Clientes'},{id:'finance',label:'Financeiro',disabled:!moduleEnabled('financeiro')},{id:'plans',label:'Planos'},{id:'surveys',label:'Pesquisas',disabled:!moduleEnabled('pesquisas')},{id:'forms',label:'Formulários',disabled:!moduleEnabled('formularios')},{id:'users',label:'Usuários'},{id:'responses',label:'Respostas'},{id:'reports',label:'Relatórios',disabled:!moduleEnabled('relatorios')},{id:'actionPlans',label:'Plano de ação',disabled:!moduleEnabled('actionPlans')},{id:'modules',label:'Módulos'},{id:'settings',label:'Configurações'},{id:'backup',label:'Backup'},{id:'logs',label:'Logs'}];
}

function portalTitle(scope,tab){
  const map={dashboard:scope==='admin'?'Visão global':scope==='empresa'?'Visão geral da empresa':'Minha área',clients:'Clientes',finance:'Financeiro',plans:'Planos comerciais',surveys:'Pesquisas e links seguros',forms:'Formulários e provas',users:'Usuários',responses:'Respostas e resultados',reports:'Central de relatórios',modules:'Módulos do sistema',settings:scope==='empresa'?'Dados da empresa':'Home, e-mail e LGPD',backup:'Backup e migração',logs:'Logs de auditoria',available:'Pesquisas disponíveis',certificates:'Certificados',privacy:'Privacidade e LGPD',plan:'Plano contratado',actionPlans:'Plano de ação'};return map[tab]||'Área';
}
