function renderPortalTab(scope,tab){
  const root=$('#portalContent');root.innerHTML=`<div class="page-head"><div><div class="breadcrumb">${scope==='admin'?'Operação Valora':scope==='empresa'?'Portal da empresa':'Portal do participante'} › ${esc(portalTitle(scope,tab))}</div><h1 class="page-title">${esc(portalTitle(scope,tab))}</h1></div><button class="btn btn-soft help-button" data-action="pageHelp" data-scope="${scope}" data-tab="${tab}">Como usar esta página</button></div><div class="page-help"><b>Você está em:</b> ${esc(portalHelp(scope,tab))}</div><div id="tabBody"></div>`;
  const body=$('#tabBody',root);if(scope==='admin')renderAdminTab(tab,body);else if(scope==='empresa')renderCompanyTab(tab,body);else renderParticipantTab(tab,body);
  enhanceResponsiveTables(body);
}
function enhanceResponsiveTables(root=document){
  $$('.table',root).forEach(table=>{
    const labels=$$('thead th',table).map(th=>th.textContent.trim());
    $$('tbody tr',table).forEach(row=>{
      $$('td',row).forEach((cell,index)=>{
        if(labels[index]&&!cell.hasAttribute('data-label'))cell.setAttribute('data-label',labels[index]);
      });
    });
  });
}

function renderAdminTab(tab,body){
  const map={dashboard:adminDashboard,actionPlans:()=>actionPlansSection('admin'),clients:clientsSection,finance:financeSection,plans:plansSection,surveys:()=>surveysSection('admin'),forms:()=>formsSection('admin'),users:()=>usersSection('admin'),responses:()=>responsesSection('admin'),reports:()=>reportsSection('admin'),modules:modulesSection,settings:settingsSection,backup:backupSection,logs:logsSection};
  body.innerHTML=(map[tab]||adminDashboard)();
}
function renderCompanyTab(tab,body){
  const map={dashboard:companyDashboard,actionPlans:()=>actionPlansSection('company'),surveys:()=>surveysSection('company'),forms:()=>formsSection('company'),users:()=>usersSection('company'),responses:()=>responsesSection('company'),reports:()=>reportsSection('company'),plan:companyPlanSection,settings:companySettingsSection};body.innerHTML=(map[tab]||companyDashboard)();
}
function renderParticipantTab(tab,body){
  const map={dashboard:participantDashboard,available:participantAvailable,responses:participantResponses,certificates:participantCertificates,privacy:participantPrivacy};body.innerHTML=(map[tab]||participantDashboard)();
}

function kpi(label,value,detail='',tone=''){return `<div class="kpi ${tone}"><span>${esc(label)}</span><strong>${esc(value)}</strong><small>${esc(detail)}</small></div>`;}
function barList(items){return renderHorizontalBars(items);}
function renderHorizontalBars(items=[]){if(!items.length)return '<div class="empty">Sem dados para exibir.</div>';return `<div class="metric-list">${items.map(x=>`<div class="metric-row"><div><b>${esc(x.label)}</b><span>${esc(x.valueLabel||x.value||'0')}</span></div><div class="bar" aria-label="${esc(x.label)} ${esc(x.valueLabel||x.value||'0')}"><span style="width:${clamp(x.percent??x.percentage,0,100)}%"></span></div></div>`).join('')}</div>`;}
function renderBarChart(items=[]){if(!items.length)return '<div class="empty">Sem dados para exibir.</div>';const max=Math.max(1,...items.map(i=>Number(i.value||0)));return `<div class="chart-columns">${items.map(i=>`<div class="chart-col"><b>${esc(i.valueLabel||i.value||0)}</b><div class="col" style="height:${clamp(Number(i.value||0)/max*100,3,100)}%"></div><span>${esc(i.label)}</span></div>`).join('')}</div>`;}
function renderTrendLine(points=[]){if(!points.length)return '<div class="empty">Sem série histórica.</div>';const max=Math.max(1,...points.map(p=>Number(p.value||0)));return `<div class="trend-line">${points.map(p=>`<div class="trend-point"><span style="height:${clamp(Number(p.value||0)/max*100,4,100)}%"></span><b>${esc(p.value)}</b><small>${esc(p.label)}</small></div>`).join('')}</div>`;}
function renderDistribution(items=[]){return renderHorizontalBars(items.map(i=>({label:i.label,valueLabel:`${i.value||0} resposta(s)`,percent:items.reduce((s,x)=>s+Number(x.value||0),0)?Number(i.value||0)/items.reduce((s,x)=>s+Number(x.value||0),0)*100:0})));}
function renderRanking(items=[]){if(!items.length)return '<div class="empty">Sem dados para ranking.</div>';return `<div class="ranking-list">${items.map((i,idx)=>`<div><b>${idx+1}. ${esc(i.label)}</b><span>${esc(i.valueLabel||i.value||'')}</span></div>`).join('')}</div>`;}
function renderProgressRing(value){return `<div class="progress-ring"><strong>${clamp(value,0,100)}%</strong></div>`;}
function onboardingMetrics(companyId){
  const c=companyById(companyId), plan=planById(c?.planId), users=state.users.filter(u=>u.companyId===companyId), employees=users.filter(u=>COMPANY_ROLES.includes(u.role)&&u.role!=='empresa_admin'), admins=users.filter(u=>u.role==='empresa_admin'&&u.status!=='inactive'), forms=scopedForms(companyId), ownForms=forms.filter(f=>f.companyId===companyId||f.global), surveys=scopedSurveys(companyId), activeSurveys=surveys.filter(s=>surveyIsActive(s)), invitations=state.invitations.filter(i=>i.companyId===companyId), responses=scopedResponses(companyId), reports=responses.length;
  const basic=!!(c?.name&&(c.email||c.phone||c.document||c.address));
  const checks=[
    {id:'company',label:'Dados da empresa revisados',weight:10,done:basic,action:'portalTab',scope:'empresa',tab:'settings',button:'Revisar dados',text:'Confirme nome, contato, endereço, responsável e área principal.'},
    {id:'plan',label:'Plano contratado definido',weight:10,done:!!plan,action:'portalTab',scope:'empresa',tab:'plan',button:'Ver plano',text:'Confira limites, módulos e se o envio por e-mail está incluso.'},
    {id:'admin',label:'Administrador da empresa configurado',weight:10,done:admins.length>0,action:'newUser',button:'Configurar admin',text:'Mantenha ao menos um administrador ativo para operar o ambiente.'},
    {id:'employees',label:'Funcionários/respondentes cadastrados',weight:15,done:employees.length>0,action:'newUser',button:'Cadastrar funcionários',text:'Cadastre respondentes com e-mail, perfil, departamento e status.'},
    {id:'forms',label:'Questionário criado ou escolhido',weight:15,done:ownForms.length>0,action:'newForm',button:'Criar questionário',text:'Use um modelo global ou crie o Diagnóstico Essencial de Maturidade.'},
    {id:'surveys',label:'Pesquisa criada',weight:15,done:activeSurveys.length>0,action:'newSurvey',button:'Criar pesquisa',text:'Transforme um questionário em campanha com validade e LGPD.'},
    {id:'invites',label:'Convites enviados',weight:10,done:invitations.length>0,action:'bulkInvite',button:'Enviar convites',text:'Selecione uma pesquisa ativa e envie convites por e-mail.'},
    {id:'responses',label:'Primeira resposta recebida',weight:10,done:responses.length>0,action:'portalTab',scope:'empresa',tab:'responses',button:'Ver respostas',text:'Acompanhe a taxa de resposta e reenvie lembretes se necessário.'},
    {id:'reports',label:'Relatório inicial gerado',weight:5,done:reports>0,action:'portalTab',scope:'empresa',tab:'reports',button:'Gerar relatório',text:'Com ao menos uma resposta, gere o relatório inicial.'}
  ];
  let percent=checks.reduce((sum,x)=>sum+(x.done?x.weight:0),0);const next=checks.find(x=>!x.done)||checks[checks.length-1];const status=percent>=100?'implantado':responses.length?'com_respostas':invitations.length?'convites_enviados':activeSurveys.length?'pesquisa_criada':employees.length?'funcionarios_cadastrados':percent>=20?'configurando':'novo';
  const inactiveDays=Math.floor((Date.now()-new Date(c?.updatedAt||c?.createdAt||Date.now()))/86400000);return {company:c,plan,checks,percent,next,status:inactiveDays>14&&percent<80?'travado':status,employees,forms,surveys,activeSurveys,invitations,responses};
}
function onboardingCard(companyId){const m=onboardingMetrics(companyId), canCreate=can(currentUser(),'canCreateSurveys')||can(currentUser(),'canManageCompanyUsers');return `<div class="card onboarding-card"><div class="onboarding-head"><div><span class="badge">Primeiros passos da implantação</span><h3>Implantação ${m.percent}% concluída</h3><p>Etapa atual: <b>${esc(m.next.label)}</b>. Próximo passo: ${esc(m.next.text)}</p></div><div class="progress-ring"><strong>${m.percent}%</strong></div></div><div class="bar onboarding-progress"><span style="width:${m.percent}%"></span></div>${planWarnings(companyId)}<div class="quick-actions"><button class="btn btn-primary" data-action="openOnboardingWizard" ${canCreate?'':'disabled'}>Configurar minha primeira pesquisa</button><button class="btn btn-secondary" data-action="${m.next.action}" ${m.next.scope?`data-scope="${m.next.scope}" data-tab="${m.next.tab}"`:''}>${esc(m.next.button)}</button></div><div class="onboarding-list">${m.checks.map(x=>`<div class="onboarding-step ${x.done?'done':x.id===m.next.id?'current':''}"><span>${x.done?'✓':x.id===m.next.id?'…':'○'}</span><div><b>${esc(x.label)}</b><small>${esc(x.done?'Concluído':x.id===m.next.id?'Em andamento':'Pendente')} • ${esc(x.text)}</small></div><button class="btn btn-soft btn-mini" data-action="${x.action}" ${x.scope?`data-scope="${x.scope}" data-tab="${x.tab}"`:''}>${esc(x.button)}</button></div>`).join('')}</div></div>`;}
function planWarnings(companyId){const p=getCompanyPlan(companyId);const u=currentUser();let out='';if(p&&p.allowEmailSending===false)out+='<div class="notice warn">Seu plano atual não inclui envio por e-mail. Fale com a Valora para ativar.</div>';if(u&&!can(u,'canCreateSurveys'))out+='<div class="notice warn">Seu perfil permite acompanhar resultados, mas não criar pesquisas.</div>';return out;}
function smartEmpty(kind){const map={employees:['Nenhum funcionário cadastrado ainda.','Cadastre os primeiros respondentes para enviar pesquisas e acompanhar resultados por área.','Cadastrar funcionário','newUser'],forms:['Nenhum questionário criado.','Crie um questionário próprio ou use um modelo global para iniciar seu diagnóstico.','Criar questionário','newForm'],surveys:['Nenhuma pesquisa ativa.','Crie uma pesquisa a partir de um questionário e envie convites aos funcionários.','Criar pesquisa','newSurvey'],invites:['Nenhum convite enviado.','Selecione uma pesquisa ativa e envie para os funcionários cadastrados.','Enviar convites','bulkInvite'],responses:['Ainda não há respostas.','Quando os participantes concluírem a pesquisa, os resultados aparecerão aqui.','Reenviar convites','bulkInvite'],reports:['Relatório ainda indisponível.','Você precisa ter pelo menos uma resposta concluída para gerar um relatório.','Ver pesquisas','portalTab']};const x=map[kind];return `<div class="card empty-smart"><h3>${x[0]}</h3><p>${x[1]}</p><button class="btn btn-primary" data-action="${x[3]}" ${kind==='reports'?'data-scope="empresa" data-tab="surveys"':''}>${x[2]}</button></div>`;}
function onboardingStatusBadge(companyId){const m=onboardingMetrics(companyId);return `<span class="badge ${m.status==='travado'?'danger':m.status==='implantado'?'success':'warn'}">${esc(m.status)} • ${m.percent}%</span>`;}

function adminDashboard(){
  const m=window.ValoraAnalytics.getGlobalDashboardMetrics(state), actionRows=state.actionPlans||[], actionM=actionPlanMetrics(actionRows);
  const statusCounts={};m.onboarding.forEach(o=>statusCounts[o.status]=(statusCounts[o.status]||0)+1);
  const commercialAlerts=[
    ...state.companies.filter(c=>!state.users.some(u=>u.companyId===c.id&&u.role==='empresa_admin'&&u.status!=='inactive')).map(c=>({company:c,label:'Empresa sem administrador',cta:'abrir cliente'})),
    ...state.companies.filter(c=>!state.users.some(u=>u.companyId===c.id&&u.role!=='empresa_admin')).map(c=>({company:c,label:'Empresa sem funcionários',cta:'abrir ambiente'})),
    ...state.companies.filter(c=>!state.surveys.some(s=>s.companyId===c.id&&surveyIsActive(s))).map(c=>({company:c,label:'Sem pesquisa ativa',cta:'ver pesquisas'})),
    ...m.nearLimit.map(c=>({company:c,label:'Próxima do limite do plano',cta:'revisar plano'}))
  ].slice(0,10);
  const topCompanies=state.companies.map(c=>{const x=window.ValoraAnalytics.getInvitationMetrics(state,c.id);return {label:c.name,value:x.responseRate,valueLabel:`${x.responseRate}% • ${x.completed}/${x.sent}`};}).sort((a,b)=>b.value-a.value).slice(0,6);
  return `<div class="kpi-grid">${kpi('Clientes totais',m.totalClients,'ambientes cadastrados')}${kpi('Clientes ativos',m.activeClients,`${m.inactiveClients} suspensos/inativos`)}${kpi('Em implantação',m.onboarding.filter(o=>o.status!=='implantado').length,'clientes em progresso','warn')}${kpi('Clientes travados',m.stuck.length,'sem avanço recente',m.stuck.length?'danger':'')}${kpi('MRR estimado',money(m.mrr),'planos ativos','success')}${kpi('Plano mais utilizado',m.topPlan?.label||'—',`${m.topPlan?.value||0} cliente(s)`)}${kpi('Respostas no mês',responsesThisMonth(),`${m.responses.totalCompleted} concluídas`)}${kpi('Taxa média resposta',`${m.invites.responseRate}%`,`${m.invites.completed}/${m.invites.sent} convites`)}${kpi('Ações vencidas',actionM.overdue,'plano de ação global',actionM.overdue?'danger':'')}${kpi('Progresso ações',actionM.avgProgress+'%','média global')}</div>
  <div class="grid grid-2 dashboard-grid"><div class="card"><h3>Clientes por plano</h3>${renderBarChart(m.plans.map(p=>({label:p.label,value:p.value,valueLabel:p.value})))}</div><div class="card"><h3>Status de implantação</h3>${renderHorizontalBars(Object.entries(statusCounts).map(([label,value])=>({label,valueLabel:`${value} empresa(s)`,percent:m.totalClients?value/m.totalClients*100:0})))}</div><div class="card"><h3>MRR por plano</h3>${renderHorizontalBars(m.plans.map(p=>({label:p.label,valueLabel:money(p.mrr),percent:m.mrr?p.mrr/m.mrr*100:0})))}</div><div class="card"><h3>Respostas por mês</h3>${renderTrendLine(m.series)}</div><div class="card"><h3>Melhor taxa de resposta</h3>${renderRanking(topCompanies)}</div><div class="card commercial-alerts"><h3>Atenção comercial</h3>${commercialAlerts.map(a=>`<div class="alert-row"><div><b>${esc(a.label)}</b><span>${esc(a.company.name)} • ${esc(a.cta)}</span></div><button class="btn btn-soft btn-mini" data-action="impersonateCompany" data-id="${a.company.id}">Abrir cliente</button></div>`).join('')||'<div class="empty">Nenhum alerta comercial crítico.</div>'}</div></div>`;
}
function companyDashboard(){
  const c=currentCompany();if(!c)return `<div class="danger-box">Selecione ou acesse uma empresa para visualizar o painel.</div>`;const m=window.ValoraAnalytics.getCompanyDashboardMetrics(state,c.id), p=planById(c.planId), r=m.responses, inv=m.invites, actionRows=actionPlansForUser(c.id), actionM=actionPlanMetrics(actionRows);
  const nextDue=m.onboarding.activeSurveys.map(s=>({s,days:Math.ceil((toDateValue(s.expiresAt)-Date.now())/86400000)})).sort((a,b)=>a.days-b.days)[0];
  const role=currentUser()?.role, canOperate=!['analista_resultados','gestor_area'].includes(role);
  return `${onboardingCard(c.id)}<div class="kpi-grid">${kpi('Funcionários',m.onboarding.employees.length,'respondentes cadastrados')}${kpi('Pesquisas ativas',m.onboarding.activeSurveys.length,`${m.onboarding.surveys.length} no histórico`)}${kpi('Convites enviados',inv.sent,'status sent/opened/answered/resent')}${kpi('Respostas concluídas',r.totalCompleted,`${inv.responseRate}% de taxa de resposta`)}${kpi('Média geral',r.totalCompleted?r.normalized5.toFixed(2)+'/5':'—',`${Math.round(r.percentage||0)}%`)}${kpi('Dimensão forte',r.bestDimension?.label||'—',r.bestDimension?`${r.bestDimension.normalized5.toFixed(2)}/5`:'aguardando')}${kpi('Dimensão crítica',r.criticalDimension?.label||'—',r.criticalDimension?`${r.criticalDimension.normalized5.toFixed(2)}/5`:'aguardando')}${kpi('Uso do plano',p?.name||'—',nextDue?`vence em ${nextDue.days} dia(s)`:'sem prazo próximo')}${kpi('Ações pendentes',actionM.pending,'plano de ação')}${kpi('Ações vencidas',actionM.overdue,'exigem revisão',actionM.overdue?'danger':'')}${kpi('Ações críticas',actionM.critical,'prioridade crítica',actionM.critical?'danger':'')}${kpi('Progresso ações',actionM.avgProgress+'%','média do plano')}</div>
  <div class="grid grid-2 dashboard-grid"><div class="card"><h3>Uso do plano</h3>${renderHorizontalBars(m.usage.items.map(i=>({label:i.label,valueLabel:`${i.used} / ${i.limit<0?'Ilimitado':i.limit}`,percent:i.limit<0?0:i.percentage})))}</div><div class="card"><h3>Resultado por dimensão</h3>${r.dimensions.length?renderHorizontalBars(r.dimensions.map(d=>({label:d.label,valueLabel:`${d.normalized5.toFixed(2)}/5`,percent:d.percentage}))):'<div class="empty">Os resultados aparecerão aqui assim que os participantes responderem.</div>'}</div><div class="card"><h3>Evolução das respostas</h3>${renderTrendLine(m.series)}</div><div class="card"><h3>Distribuição por faixa</h3>${renderDistribution(r.distribution)}</div><div class="card"><h3>Pontos fortes e críticos</h3><p><b>Forte:</b> ${esc(r.bestDimension?.label||'aguardando respostas')}</p><p><b>Crítica:</b> ${esc(r.criticalDimension?.label||'aguardando respostas')}</p>${m.recommendations.map(x=>`<div class="notice warn"><b>${esc(x.label)}:</b> ${esc(x.text)}</div>`).join('')||'<p class="muted">Sem alertas automáticos no momento.</p>'}</div><div class="card"><h3>Ações rápidas</h3>${canOperate?'<div class="quick-actions"><button class="btn btn-primary" data-action="newSurvey">Criar pesquisa</button><button class="btn btn-secondary" data-action="bulkInvite">Enviar convites</button><button class="btn btn-soft" data-action="portalTab" data-scope="empresa" data-tab="responses">Ver respostas</button></div>':'<p class="muted">Perfil analítico: leitura de indicadores e relatórios sem ações administrativas.</p>'}</div></div>`;
}
function participantDashboard(){
  const u=currentUser();const responses=responsesForUser(u);const available=activeSurveysForParticipant();const average=avg(responses.map(r=>r.normalized5));return `<div class="kpi-grid">${kpi('Pesquisas disponíveis',available.length,'Links ativos no seu ambiente')}${kpi('Pesquisas respondidas',responses.length,'Seu histórico pessoal')}${kpi('Média geral',average?average.toFixed(2)+'/5':'—','Resultados normalizados')}${kpi('Certificados',responses.length,'Um por conclusão')}</div><div class="grid grid-2"><div class="card"><h3>Continuar jornada</h3>${miniSurveysTable(available.slice(0,4),true)}</div><div class="card"><h3>Resultados recentes</h3>${miniResponsesTable(responses.slice(0,4),true)}</div></div>`;}

function clientsSection(){return `<div class="section-toolbar"><div><h3>Clientes e ambientes</h3><p class="muted">Plano, status, uso, CNPJ/CPF e dados de contato.</p></div><button class="btn btn-primary" data-action="newCompany">Cadastrar cliente</button></div><div class="card table-wrap"><table class="table"><thead><tr><th>Cliente</th><th>Documento</th><th>Plano</th><th>Uso</th><th>Status</th><th>Ações</th></tr></thead><tbody>${state.companies.map(c=>`<tr><td><b>${esc(c.name)}</b><br><span class="muted">${esc(c.email||'')}</span></td><td>${esc(c.document||'—')}</td><td>${esc(planById(c.planId)?.name||'—')}<br><span class="muted">${money(planById(c.planId)?.price||0)}/mês</span></td><td>${scopedSurveys(c.id).filter(s=>surveyIsActive(s)).length} pesquisas<br>${responsesThisMonth(c.id)} respostas/mês</td><td><span class="badge ${c.status==='active'?'success':'danger'}">${esc(STATUS_LABELS[c.status]||c.status)}</span></td><td><div class="table-actions"><button class="btn btn-soft btn-mini" data-action="editCompany" data-id="${c.id}">Editar</button><button class="btn btn-secondary btn-mini" data-action="impersonateCompany" data-id="${c.id}">Abrir ambiente</button><button class="btn btn-danger btn-mini" data-action="deleteCompany" data-id="${c.id}">Excluir</button></div></td></tr>`).join('')}</tbody></table></div>`;}
function financeSection(){
  const mrr=state.companies.filter(c=>c.status==='active').reduce((s,c)=>s+Number(planById(c.planId)?.price||0),0);const paid=state.invoices.filter(i=>i.status==='paid').reduce((s,i)=>s+Number(i.amount||0),0);const open=state.invoices.filter(i=>i.status!=='paid').reduce((s,i)=>s+Number(i.amount||0),0);
  return `<div class="kpi-grid">${kpi('MRR contratado',money(mrr),'Planos de clientes ativos')}${kpi('Recebido registrado',money(paid),'Histórico de faturas pagas','success')}${kpi('Em aberto',money(open),'Faturas abertas ou vencidas',open?'warn':'')}${kpi('Faturas',state.invoices.length,'Registros financeiros')}</div><div class="section-toolbar"><div><h3>Faturas</h3><p class="muted">Os valores são derivados dos planos contratados e registros financeiros.</p></div><button class="btn btn-primary" data-action="newInvoice">Nova fatura</button></div><div class="card table-wrap"><table class="table"><thead><tr><th>Cliente</th><th>Valor</th><th>Vencimento</th><th>Status</th><th>Ações</th></tr></thead><tbody>${state.invoices.map(i=>`<tr><td>${esc(companyName(i.companyId))}</td><td>${money(i.amount)}</td><td>${brDay(i.dueAt)}</td><td><span class="badge ${i.status==='paid'?'success':i.status==='overdue'?'danger':'warn'}">${esc(STATUS_LABELS[i.status]||i.status)}</span></td><td><div class="table-actions"><button class="btn btn-soft btn-mini" data-action="editInvoice" data-id="${i.id}">Editar</button><button class="btn btn-danger btn-mini" data-action="deleteInvoice" data-id="${i.id}">Excluir</button></div></td></tr>`).join('')||'<tr><td colspan="5">Nenhuma fatura cadastrada.</td></tr>'}</tbody></table></div>`;
}
function planCompanies(id){return state.companies.filter(c=>c.planId===id);}
function planStatus(p){return p.status||'active';}
function planLimit(v){return Number(v)<0?'Ilimitado':Number(v||0).toLocaleString('pt-BR');}
function planModules(p){return Array.isArray(p.enabledModules)?p.enabledModules:defaultEnabledModules(p,state.modules);}
function defaultEnabledModules(p,modules=null){const source=modules||(globalThis.__valoraModulesForPlan||seedModules());const ids=source.filter(m=>m.enabled!==false).map(m=>m.id);return ids.length?ids:['pesquisas','formularios','relatorios'];}
function planFeatures(p){return Array.isArray(p.features)?p.features:[];}
function plansSection(){
  const paid=state.companies.filter(c=>Number(planById(c.planId)?.price||0)>0);
  const activePlans=state.plans.filter(p=>planStatus(p)==='active');
  const mrr=state.companies.reduce((sum,c)=>sum+Number(planById(c.planId)?.price||0),0);
  const ranked=state.plans.map(p=>({p,count:planCompanies(p.id).length})).sort((a,b)=>b.count-a.count)[0];
  const def=defaultPlan();
  return `<div class="section-toolbar plan-admin-head"><div><h2>Planos comerciais</h2><p class="section-lead">Configure preços, limites, recursos e regras comerciais disponíveis para cada empresa.</p></div><button class="btn btn-primary" data-action="newPlan">Novo plano</button></div>
  <div class="kpi-grid plan-kpis"><div class="kpi"><span>Total de planos</span><strong>${state.plans.length}</strong><em>Cadastrados</em></div><div class="kpi success"><span>Planos ativos</span><strong>${activePlans.length}</strong><em>Disponíveis para novos clientes</em></div><div class="kpi"><span>Clientes pagos</span><strong>${paid.length}</strong><em>Empresas em planos com preço</em></div><div class="kpi"><span>MRR estimado</span><strong>${money(mrr)}</strong><em>Base atual vinculada</em></div><div class="kpi"><span>Plano padrão</span><strong>${esc(def?.name||'—')}</strong><em>Novos cadastros</em></div><div class="kpi"><span>Mais clientes</span><strong>${esc(ranked?.p?.name||'—')}</strong><em>${ranked?.count||0} cliente(s)</em></div></div>
  <div class="grid grid-4 admin-plan-grid">${state.plans.map(p=>planAdminCard(p)).join('')}</div>`;
}
function planAdminCard(p){
  const clients=planCompanies(p.id).length, active=planStatus(p)==='active';
  return `<div class="card plan-card admin-plan-card ${p.highlight?'featured':''} ${active?'':'inactive'}"><div class="plan-badges"><span class="status ${active?'':'off'}">${active?'Ativo':'Inativo'}</span>${p.default?'<span class="badge">Padrão</span>':''}${p.highlight?'<span class="badge dark">Destaque</span>':''}</div><h3>${esc(p.name)}</h3><div class="price">${p.price?`${money(p.price)} <small>/mês</small>`:'Grátis'}</div><p>${esc(p.description)}</p><div class="plan-limits"><span>Pesquisas: <b>${planLimit(p.maxActiveSurveys)}</b></span><span>Respostas/mês: <b>${planLimit(p.maxResponsesMonth)}</b></span><span>Gestores: <b>${planLimit(p.maxManagers)}</b></span><span>Respondentes: <b>${planLimit(p.maxEmployees??p.maxRespondents??0)}</b></span><span>Clientes: <b>${clients}</b></span></div><div class="feature-list">${planFeatures(p).slice(0,6).map(f=>`<div class="feature">${esc(f)}</div>`).join('')}</div><div class="table-actions plan-actions"><button class="btn btn-primary btn-mini" data-action="editPlan" data-id="${p.id}">Editar</button><button class="btn btn-soft btn-mini" data-action="duplicatePlan" data-id="${p.id}">Duplicar</button><button class="btn btn-soft btn-mini" data-action="setDefaultPlan" data-id="${p.id}" ${p.default?'disabled':''}>Definir padrão</button><button class="btn btn-soft btn-mini" data-action="togglePlanHighlight" data-id="${p.id}">${p.highlight?'Remover destaque':'Destacar'}</button><button class="btn btn-soft btn-mini" data-action="togglePlanStatus" data-id="${p.id}">${active?'Inativar':'Ativar'}</button>${clients?'<button class="btn btn-danger btn-mini" disabled>Excluir</button>':`<button class="btn btn-danger btn-mini" data-action="deletePlan" data-id="${p.id}">Excluir</button>`}</div></div>`;
}
function surveysSection(scope){
  const list=scope==='admin'?state.surveys:scopedSurveys(currentCompany()?.id);return `<div class="section-toolbar"><div><h3>Campanhas e links seguros</h3><p class="muted">Crie, escolha validade, renove token, destaque na home e compartilhe.</p></div><div class="table-actions"><button class="btn btn-success" data-action="quickSurvey">Criar e compartilhar agora</button><button class="btn btn-primary" data-action="newSurvey">Nova pesquisa</button></div></div>${!list.length&&scope!=='admin'?smartEmpty('surveys'):miniSurveysTable(list,false,scope==='admin')}`;
}
function miniSurveysTable(list,participant=false,admin=false){return `<div class="card table-wrap"><table class="table"><thead><tr><th>Pesquisa</th><th>Empresa</th><th>Validade</th><th>Status</th><th>Respostas</th><th>Ações</th></tr></thead><tbody>${list.map(s=>`<tr><td><b>${esc(s.title)}</b><br><span class="muted">${esc(formById(s.formId)?.name||'Formulário removido')}</span>${state.settings.featuredSurveyId===s.id?'<br><span class="badge success">Destaque da home</span>':''}</td><td>${esc(companyName(s.companyId))}</td><td>${brDay(s.expiresAt)}<br><span class="muted">${daysUntil(s.expiresAt)}</span></td><td><span class="badge ${surveyIsActive(s)?'success':'danger'}">${surveyIsActive(s)?'Ativa':isExpired(s)?'Expirada':esc(STATUS_LABELS[s.status]||s.status)}</span></td><td>${state.responses.filter(r=>r.surveyId===s.id).length}</td><td><div class="table-actions">${participant?`<button class="btn btn-primary btn-mini" data-action="openSurvey" data-id="${s.id}">Responder</button>`:`<button class="btn btn-success btn-mini" data-action="shareSurvey" data-id="${s.id}">Compartilhar</button><button class="btn btn-soft btn-mini" data-action="editSurvey" data-id="${s.id}">Editar</button>${admin?`<button class="btn btn-secondary btn-mini" data-action="featureSurvey" data-id="${s.id}">${state.settings.featuredSurveyId===s.id?'Em destaque':'Destacar na home'}</button>`:''}<button class="btn btn-danger btn-mini" data-action="deleteSurvey" data-id="${s.id}">Excluir</button>`}</div></td></tr>`).join('')||'<tr><td colspan="6">Nenhuma pesquisa encontrada.</td></tr>'}</tbody></table></div>`;}
function formsSection(scope){
  const list=scope==='admin'?state.forms:scopedForms(currentCompany()?.id);if(!list.length&&scope!=='admin')return smartEmpty('forms');return `<div class="section-toolbar"><div><h3>Biblioteca de formulários e provas</h3><p class="muted">Cada pergunta pode usar um tipo próprio, nota, peso e opções. Salve, revise, edite, exclua ou transforme em pesquisa compartilhável.</p></div><button class="btn btn-primary" data-action="newForm">Criar novo formulário</button></div><div class="card table-wrap"><table class="table"><thead><tr><th>Formulário</th><th>Categoria</th><th>Tempo</th><th>Perguntas</th><th>Método</th><th>Ações</th></tr></thead><tbody>${list.map(f=>`<tr><td><b>${esc(f.name)}</b><br><span class="muted">${esc(f.description)}</span>${f.global?'<br><span class="badge">Modelo Valora</span>':''}</td><td>${esc(f.category||'Personalizado')}</td><td>${Number(f.timeMin||5)} min</td><td>${f.questions.length}</td><td>${scoringLabel(f.scoringMethod)}</td><td><div class="table-actions"><button class="btn btn-primary btn-mini" data-action="shareForm" data-id="${f.id}">Criar pesquisa e compartilhar</button><button class="btn btn-soft btn-mini" data-action="previewForm" data-id="${f.id}">Prévia</button><button class="btn btn-secondary btn-mini" data-action="editForm" data-id="${f.id}">${f.global&&scope!=='admin'?'Clonar e editar':'Editar'}</button><button class="btn btn-soft btn-mini" data-action="cloneForm" data-id="${f.id}">Clonar</button>${!f.global||scope==='admin'?`<button class="btn btn-danger btn-mini" data-action="deleteForm" data-id="${f.id}">Excluir</button>`:''}</div></td></tr>`).join('')}</tbody></table></div>`;}
function usersSection(scope){
  const companyId=currentCompany()?.id;let list=scope==='admin'?state.users:state.users.filter(u=>u.companyId===companyId);const isCompany=scope!=='admin';
  const roles=isCompany?COMPANY_ROLES:Object.keys(ROLE_DEFINITIONS);const departments=[...new Set(list.map(u=>u.department||u.area).filter(Boolean))].sort();
  if(isCompany&&!list.length)return smartEmpty('employees');return `<div class="section-toolbar"><div><h3>${isCompany?'Funcionários e respondentes':'Usuários e perfis'}</h3><p class="muted">Perfis, permissões, status, convites e segmentação por área. Empresas nunca podem criar perfis globais Valora.</p></div><div class="table-actions"><button class="btn btn-primary" data-action="newUser">${isCompany?'Cadastrar funcionário':'Cadastrar usuário'}</button>${isCompany?'<button class="btn btn-secondary" data-action="bulkInvite">Enviar pesquisa aos selecionados</button>':''}</div></div>${isCompany?`<div class="card filters"><input data-input="userFilter" id="employeeSearch" placeholder="Pesquisar por nome, e-mail ou cargo"><select data-input="userFilter" id="employeeRole"><option value="">Todos os perfis</option>${roles.map(r=>`<option value="${r}">${esc(ROLE_LABELS[r])}</option>`).join('')}</select><select data-input="userFilter" id="employeeStatus"><option value="">Todos os status</option><option value="active">Ativos</option><option value="inactive">Inativos</option></select><select data-input="userFilter" id="employeeDepartment"><option value="">Todas as áreas</option>${departments.map(d=>`<option value="${esc(d)}">${esc(d)}</option>`).join('')}</select><select data-input="userFilter" id="employeeEmail"><option value="">E-mail pesquisa</option><option value="true">Recebe</option><option value="false">Não recebe</option></select><select data-input="userFilter" id="employeePortal"><option value="">Acesso portal</option><option value="true">Com acesso</option><option value="false">Sem acesso</option></select><button class="btn btn-soft btn-mini" data-action="selectAllEmployees">Selecionar todos</button><button class="btn btn-soft btn-mini" data-action="clearEmployees">Limpar seleção</button><span class="badge" id="employeeSelectedCount">0 selecionados</span></div>`:''}<div class="card table-wrap"><table class="table" id="usersTable"><thead><tr>${isCompany?'<th>Selecionar</th>':''}<th>Usuário</th><th>Perfil</th><th>Departamento</th><th>Status</th><th>Convites</th><th>Respostas</th><th>Ações</th></tr></thead><tbody>${list.map(u=>{const inv=state.invitations.filter(i=>i.email?.toLowerCase()===u.email?.toLowerCase()).length;const resp=state.responses.filter(r=>r.participant?.email?.toLowerCase()===u.email?.toLowerCase()).length;return `<tr data-user-row data-name="${esc((u.name+' '+u.email+' '+(u.position||'')).toLowerCase())}" data-role="${esc(u.role)}" data-status="${esc(u.status||'active')}" data-department="${esc(u.department||u.area||'')}" data-email="${u.receivesEmail!==false}" data-portal="${u.portalAccess!==false}">${isCompany?`<td><input type="checkbox" data-employee-check value="${u.id}" ${u.status==='inactive'||!u.email||u.receivesEmail===false?'disabled':''}></td>`:''}<td><b>${esc(u.name)}</b><br><span class="muted">${esc(u.email)}</span><br><span class="muted">${esc(u.phone||'')}</span><br><span class="muted">${esc(u.position||u.jobTitle||'Sem cargo')}</span></td><td><b>${esc(ROLE_LABELS[u.role]||u.role)}</b><br><span class="muted">${esc(getRoleDefinition(u.role).description)}</span></td><td>${esc(u.department||u.area||'—')}</td><td><span class="badge ${u.status==='active'?'success':'danger'}">${esc(STATUS_LABELS[u.status]||u.status)}</span><br><span class="muted">Portal: ${u.portalAccess===false?'não':'sim'} • E-mail: ${u.receivesEmail===false?'não':'sim'}</span></td><td>${inv}</td><td>${resp}</td><td><div class="table-actions"><button class="btn btn-soft btn-mini" data-action="editUser" data-id="${u.id}">Editar</button><button class="btn btn-secondary btn-mini" data-action="bulkInvite" ${isCompany?'':'disabled'}>Enviar pesquisa</button><button class="btn btn-warning btn-mini" data-action="toggleUserStatus" data-id="${u.id}">${u.status==='inactive'?'Reativar':'Desativar'}</button><button class="btn btn-danger btn-mini" data-action="deleteUser" data-id="${u.id}">Excluir</button></div></td></tr>`}).join('')}</tbody></table></div>`;}

function responsesSection(scope){const companyId=scope==='admin'?'':currentCompany()?.id;const list=window.ValoraAnalytics.completedResponses(state,{companyId});const m=window.ValoraAnalytics.getResponseMetrics(state,{companyId});if(scope!=='admin'&&!list.length)return smartEmpty('responses');return `<div class="section-toolbar"><div><h3>Respostas e resultados</h3><p class="muted">Resumo analítico, filtros aplicados e tabela usam os mesmos indicadores dos dashboards.</p></div><button class="btn btn-secondary" data-action="exportReport" data-scope="${scope}" data-format="pdf">Relatório PDF</button></div><div class="kpi-grid">${kpi('Total de respostas',m.totalCompleted,'somente concluídas')}${kpi('Média geral',m.totalCompleted?m.normalized5.toFixed(2)+'/5':'—','normalized5')}${kpi('Melhor dimensão',m.bestDimension?.label||'—',m.bestDimension?m.bestDimension.normalized5.toFixed(2)+'/5':'sem dados')}${kpi('Pior dimensão',m.criticalDimension?.label||'—',m.criticalDimension?m.criticalDimension.normalized5.toFixed(2)+'/5':'sem dados')}</div><div class="grid grid-2 dashboard-grid"><div class="card"><h3>Respostas por faixa</h3>${renderDistribution(m.distribution)}</div><div class="card"><h3>Filtros aplicados</h3><p>Empresa: <b>${scope==='admin'?'Todas':esc(currentCompany()?.name||'—')}</b></p><p>Status: <b>Concluídas</b></p><p>Período: <b>Todo o histórico disponível</b></p></div></div>${miniResponsesTable(list,false,scope)}`;}
function miniResponsesTable(list,participant=false,scope='participant'){return `<div class="card table-wrap"><table class="table"><thead><tr><th>Participante</th><th>Pesquisa</th><th>Data</th><th>Índice</th><th>Nível</th><th>Ações</th></tr></thead><tbody>${list.map(r=>`<tr><td><b>${esc(r.participant.name)}</b><br><span class="muted">${esc(r.participant.email)}</span></td><td>${esc(surveyTitle(r.surveyId))}</td><td>${brDate(r.createdAt)}</td><td>${Number(r.normalized5||0).toFixed(2)} / 5<br><span class="muted">${Number(r.rawScore||0).toFixed(1)} / ${Number(r.maxScore||0).toFixed(1)}</span></td><td><span class="badge success">${esc(r.level?.label||'—')}</span></td><td><div class="table-actions"><button class="btn btn-primary btn-mini" data-action="viewResponse" data-id="${r.id}">Ver resultado</button><button class="btn btn-secondary btn-mini" data-action="emailResult" data-id="${r.id}">Enviar e-mail</button><button class="btn btn-soft btn-mini" data-action="certificatePdf" data-id="${r.id}">Certificado PDF</button>${!participant&&canDeleteResponse()?`<button class="btn btn-danger btn-mini" data-action="deleteResponse" data-id="${r.id}">Excluir</button>`:''}</div></td></tr>`).join('')||'<tr><td colspan="6">Nenhuma resposta encontrada.</td></tr>'}</tbody></table></div>`;}

const ACTION_PRIORITY_LABELS={low:'Baixa',medium:'Média',high:'Alta',critical:'Crítica'};
const ACTION_STATUS_LABELS={pending:'Pendente',in_progress:'Em andamento',waiting:'Aguardando',completed:'Concluída',cancelled:'Cancelada',overdue:'Vencida'};
const ACTION_SOURCE_LABELS={manual:'Manual',dimension_critical:'Dimensão crítica',survey_result:'Resultado da pesquisa',executive_report:'Relatório executivo',consultant_recommendation:'Recomendação consultiva'};
function normalizeActionPlan(a={}){return {id:a.id||uid('act'),companyId:a.companyId||'',surveyId:a.surveyId||'',responseId:a.responseId||'',reportId:a.reportId||'',dimensionId:a.dimensionId||'',dimensionName:a.dimensionName||'',questionId:a.questionId||'',title:a.title||'',description:a.description||'',source:a.source||'manual',priority:a.priority||'medium',status:a.status||'pending',responsibleUserId:a.responsibleUserId||'',responsibleName:a.responsibleName||'',department:a.department||'',dueDate:a.dueDate||'',startDate:a.startDate||nowIso(),completedAt:a.completedAt||'',progress:Number(a.progress||0),evidence:a.evidence||'',comments:Array.isArray(a.comments)?a.comments:[],createdAt:a.createdAt||nowIso(),updatedAt:a.updatedAt||nowIso(),createdBy:a.createdBy||'',updatedBy:a.updatedBy||''};}
function actionIsOverdue(a){return !['completed','cancelled'].includes(a.status)&&a.dueDate&&new Date(a.dueDate)<new Date();}
function actionEffectiveStatus(a){return actionIsOverdue(a)?'overdue':a.status;}
function actionPlansForUser(companyId=''){const u=currentUser();let rows=state.actionPlans||[];if(!GLOBAL_ROLES.includes(u?.role))rows=rows.filter(a=>a.companyId===u?.companyId);else if(companyId)rows=rows.filter(a=>a.companyId===companyId);if(u?.role==='gestor_area')rows=rows.filter(a=>(a.department||'')===(u.department||''));return rows.sort((a,b)=>new Date(a.dueDate||a.updatedAt)-new Date(b.dueDate||b.updatedAt));}
function canManageActionPlan(user,companyId){return !!user&&(user.role==='admin_valora'||user.role==='consultor_valora'||(['empresa_admin','gestor_pesquisa'].includes(user.role)&&user.companyId===companyId));}
function canViewActionPlan(user,a){return !!user&&(GLOBAL_ROLES.includes(user.role)||(['empresa_admin','gestor_pesquisa','analista_resultados'].includes(user.role)&&user.companyId===a.companyId)||(user.role==='gestor_area'&&user.companyId===a.companyId&&(a.department||'')===(user.department||'')));}
function canEditActionPlan(user,a){return canManageActionPlan(user,a.companyId)||(user?.role==='gestor_area'&&canViewActionPlan(user,a));}
function canDeleteActionPlan(user,a){return user?.role==='admin_valora'||(user?.role==='empresa_admin'&&user.companyId===a.companyId);}
function actionPlanMetrics(rows){const total=rows.length, overdue=rows.filter(actionIsOverdue).length;return {total,pending:rows.filter(a=>a.status==='pending').length,inProgress:rows.filter(a=>a.status==='in_progress').length,completed:rows.filter(a=>a.status==='completed').length,overdue,critical:rows.filter(a=>a.priority==='critical').length,avgProgress:total?Math.round(avg(rows.map(a=>a.progress))):0};}
function actionPlansSection(scope){const u=currentUser(),admin=scope==='admin',companyId=admin?($('#actionCompany')?.value||''):currentCompany()?.id,rows=actionPlansForUser(companyId),m=actionPlanMetrics(rows),companies=admin?`<select id="actionCompany" data-input="actionPlanFilter"><option value="">Todas as empresas</option>${state.companies.map(c=>`<option value="${c.id}">${esc(c.name)}</option>`).join('')}</select>`:'';return `<div class="section-toolbar"><div><h3>Plano de ação e acompanhamento de melhorias</h3><p class="muted">Fecha o ciclo Diagnóstico → Resultado → Recomendação → Plano de ação → Acompanhamento → Evolução.</p></div><div class="table-actions"><button class="btn btn-primary" data-action="newActionPlan" ${['analista_resultados'].includes(u?.role)?'disabled':''}>Nova ação</button><button class="btn btn-success" data-action="generateActionPlans" ${['analista_resultados','gestor_area'].includes(u?.role)?'disabled':''}>Gerar ações sugeridas</button></div></div><div class="kpi-grid">${kpi('Total de ações',m.total,'no escopo')}${kpi('Pendentes',m.pending,'aguardando início')}${kpi('Em andamento',m.inProgress,'em execução')}${kpi('Concluídas',m.completed,'finalizadas','success')}${kpi('Vencidas',m.overdue,'fora do prazo',m.overdue?'danger':'')}${kpi('Críticas',m.critical,'prioridade crítica',m.critical?'danger':'')}${kpi('Progresso médio',m.avgProgress+'%','ações abertas')}${kpi('Dimensões',new Set(rows.map(a=>a.dimensionName).filter(Boolean)).size,'com ações')}</div><div class="card filters action-filters">${companies}<select id="actionPriority" data-input="actionPlanFilter"><option value="">Prioridade</option>${Object.entries(ACTION_PRIORITY_LABELS).map(([k,v])=>`<option value="${k}">${v}</option>`).join('')}</select><select id="actionStatus" data-input="actionPlanFilter"><option value="">Status</option>${Object.entries(ACTION_STATUS_LABELS).map(([k,v])=>`<option value="${k}">${v}</option>`).join('')}</select><input id="actionDimension" data-input="actionPlanFilter" placeholder="Dimensão"><input id="actionResponsible" data-input="actionPlanFilter" placeholder="Responsável"><input id="actionDepartment" data-input="actionPlanFilter" placeholder="Departamento"><select id="actionSource" data-input="actionPlanFilter"><option value="">Origem</option>${Object.entries(ACTION_SOURCE_LABELS).map(([k,v])=>`<option value="${k}">${v}</option>`).join('')}</select></div><div class="grid grid-2 dashboard-grid"><div class="card"><h3>Visão por prioridade</h3>${renderHorizontalBars(Object.entries(ACTION_PRIORITY_LABELS).map(([k,v])=>({label:v,valueLabel:rows.filter(a=>a.priority===k).length+' ação(ões)',percent:m.total?rows.filter(a=>a.priority===k).length/m.total*100:0})))}</div><div class="card"><h3>Visão por dimensão</h3>${renderHorizontalBars(Object.entries(rows.reduce((acc,a)=>(acc[a.dimensionName||'Sem dimensão']=(acc[a.dimensionName||'Sem dimensão']||0)+1,acc),{})).map(([label,value])=>({label,valueLabel:value+' ação(ões)',percent:m.total?value/m.total*100:0})))}</div></div><div class="card table-wrap"><table class="table" id="actionPlansTable"><thead><tr><th>Ação</th><th>Empresa</th><th>Prioridade</th><th>Status</th><th>Responsável</th><th>Prazo</th><th>Progresso</th><th>Ações</th></tr></thead><tbody>${rows.map(a=>actionPlanRow(a)).join('')||'<tr><td colspan="8">Nenhuma ação encontrada.</td></tr>'}</tbody></table></div>`;}
function actionPlanRow(a){const st=actionEffectiveStatus(a),u=currentUser();return `<tr data-action-plan-row data-priority="${a.priority}" data-status="${st}" data-dimension="${esc((a.dimensionName||'').toLowerCase())}" data-responsible="${esc((a.responsibleName||'').toLowerCase())}" data-department="${esc((a.department||'').toLowerCase())}" data-source="${a.source}"><td><b>${esc(a.title)}</b><br><span class="muted">${esc(a.dimensionName||'Sem dimensão')} • ${esc(ACTION_SOURCE_LABELS[a.source]||a.source)}</span></td><td>${esc(companyName(a.companyId))}</td><td><span class="badge ${a.priority==='critical'?'danger':a.priority==='high'?'warn':''}">${esc(ACTION_PRIORITY_LABELS[a.priority])}</span></td><td><span class="badge ${st==='completed'?'success':st==='overdue'?'danger':'warn'}">${esc(ACTION_STATUS_LABELS[st])}</span></td><td>${esc(a.responsibleName||'A definir')}<br><span class="muted">${esc(a.department||'—')}</span></td><td>${a.dueDate?brDay(a.dueDate):'Sem prazo'}</td><td>${renderProgressRing(a.progress)}</td><td><div class="table-actions"><button class="btn btn-soft btn-mini" data-action="editActionPlan" data-id="${a.id}" ${canEditActionPlan(u,a)?'':'disabled'}>Editar</button><button class="btn btn-success btn-mini" data-action="completeActionPlan" data-id="${a.id}" ${canEditActionPlan(u,a)&&a.status!=='completed'?'':'disabled'}>Concluir</button><button class="btn btn-danger btn-mini" data-action="deleteActionPlan" data-id="${a.id}" ${canDeleteActionPlan(u,a)?'':'disabled'}>Excluir</button></div></td></tr>`;}
function openActionPlanEditor(id=''){const u=currentUser(),a=id?(state.actionPlans||[]).find(x=>x.id===id):normalizeActionPlan({companyId:currentCompany()?.id||state.companies[0]?.id,createdBy:u?.id});if(id&&!canEditActionPlan(u,a))return toast(PERMISSION_DENIED_MESSAGE,'error');const companyOptions=(GLOBAL_ROLES.includes(u?.role)?state.companies:[currentCompany()]).filter(Boolean).map(c=>`<option value="${c.id}" ${a.companyId===c.id?'selected':''}>${esc(c.name)}</option>`).join('');const users=state.users.filter(x=>!a.companyId||x.companyId===a.companyId);openModal(id?'Editar ação':'Nova ação',`<form class="grid" data-form="actionPlan"><input type="hidden" name="id" value="${esc(a.id||'')}"><div class="form-grid"><div class="field"><label>Empresa</label><select name="companyId" required ${GLOBAL_ROLES.includes(u?.role)?'':'disabled'}>${companyOptions}</select></div><div class="field"><label>Título</label><input name="title" value="${esc(a.title)}" required></div><div class="field span-2"><label>Descrição</label><textarea name="description">${esc(a.description)}</textarea></div><div class="field"><label>Prioridade</label><select name="priority" required>${Object.entries(ACTION_PRIORITY_LABELS).map(([k,v])=>`<option value="${k}" ${a.priority===k?'selected':''}>${v}</option>`).join('')}</select></div><div class="field"><label>Status</label><select name="status" required>${Object.entries(ACTION_STATUS_LABELS).filter(([k])=>k!=='overdue').map(([k,v])=>`<option value="${k}" ${a.status===k?'selected':''}>${v}</option>`).join('')}</select></div><div class="field"><label>Responsável</label><select name="responsibleUserId"><option value="">A definir</option>${users.map(x=>`<option value="${x.id}" ${a.responsibleUserId===x.id?'selected':''}>${esc(x.name)}</option>`).join('')}</select></div><div class="field"><label>Departamento</label><input name="department" value="${esc(a.department)}" ${u?.role==='gestor_area'?'readonly':''}></div><div class="field"><label>Prazo</label><input name="dueDate" type="date" value="${dateInput(a.dueDate)}"></div><div class="field"><label>Progresso</label><input name="progress" type="number" min="0" max="100" value="${a.progress}"></div><div class="field"><label>Pesquisa</label><select name="surveyId"><option value="">Sem vínculo</option>${scopedSurveys(a.companyId).map(s=>`<option value="${s.id}" ${a.surveyId===s.id?'selected':''}>${esc(s.title)}</option>`).join('')}</select></div><div class="field"><label>Dimensão</label><input name="dimensionName" value="${esc(a.dimensionName)}"></div><div class="field"><label>Origem</label><select name="source">${Object.entries(ACTION_SOURCE_LABELS).map(([k,v])=>`<option value="${k}" ${a.source===k?'selected':''}>${v}</option>`).join('')}</select></div><div class="field"><label>Relatório/Resposta/Pergunta</label><input name="reportId" value="${esc(a.reportId||a.responseId||a.questionId||'')}"></div><div class="field span-2"><label>Evidências, links e observações</label><textarea name="evidence">${esc(a.evidence)}</textarea></div><div class="field span-2"><label>Novo comentário</label><textarea name="comment"></textarea></div></div><div class="confirm-actions"><button type="button" class="btn btn-soft" data-action="closeModal">Cancelar</button><button class="btn btn-primary">Salvar ação</button></div></form>`,'large');}
function saveActionPlan(form){const fd=data(form),u=currentUser(),existing=(state.actionPlans||[]).find(a=>a.id===fd.id),companyId=fd.companyId||u?.companyId;if(!fd.title)return toast('Título obrigatório.','error');if(!companyId)return toast('Empresa obrigatória.','error');if(fd.dueDate&&Number.isNaN(new Date(fd.dueDate).getTime()))return toast('Prazo inválido.','error');if(u?.role==='gestor_area')fd.department=u.department||fd.department;if(existing&&!canEditActionPlan(u,existing))return toast(PERMISSION_DENIED_MESSAGE,'error');if(!existing&&!canManageActionPlan(u,companyId))return toast(PERMISSION_DENIED_MESSAGE,'error');const resp=state.users.find(x=>x.id===fd.responsibleUserId);const payload={companyId,title:fd.title,description:fd.description,priority:fd.priority,status:fd.status,responsibleUserId:fd.responsibleUserId||'',responsibleName:resp?.name||'',department:fd.department||resp?.department||'',dueDate:fd.dueDate?new Date(fd.dueDate+'T23:59:59').toISOString():'',progress:clamp(fd.progress,0,100),surveyId:fd.surveyId||'',dimensionName:fd.dimensionName||'',source:fd.source||'manual',reportId:fd.reportId||'',evidence:fd.evidence||'',updatedAt:nowIso(),updatedBy:u?.id};if(existing){const before={...existing};Object.assign(existing,payload);if(fd.comment)existing.comments.push({id:uid('cmt'),text:fd.comment,createdAt:nowIso(),createdBy:u?.id,userName:u?.name});audit('Ação editada','actionPlan',existing.id,`${before.status} → ${existing.status}; prazo ${before.dueDate||'—'} → ${existing.dueDate||'—'}`);}else{const a=normalizeActionPlan({id:uid('act'),...payload,createdAt:nowIso(),createdBy:u?.id});if(fd.comment)a.comments.push({id:uid('cmt'),text:fd.comment,createdAt:nowIso(),createdBy:u?.id,userName:u?.name});state.actionPlans.push(a);audit('Ação criada','actionPlan',a.id,a.title);}persist('Ação salva.');closeModal();rerenderPortal();}
function completeActionPlan(id){const a=state.actionPlans.find(x=>x.id===id),u=currentUser();if(!a||!canEditActionPlan(u,a))return toast(PERMISSION_DENIED_MESSAGE,'error');Object.assign(a,{status:'completed',progress:100,completedAt:nowIso(),updatedAt:nowIso(),updatedBy:u.id});audit('Ação concluída','actionPlan',a.id,a.title);persist('Ação concluída.');rerenderPortal();}
function deleteActionPlan(id){const a=state.actionPlans.find(x=>x.id===id),u=currentUser();if(!a||!canDeleteActionPlan(u,a))return toast(PERMISSION_DENIED_MESSAGE,'error');confirmAction('Excluir ação?',a.title,()=>{state.actionPlans=state.actionPlans.filter(x=>x.id!==id);audit('Ação excluída','actionPlan',id,a.title);persist('Ação excluída.');rerenderPortal();});}
function generateActionSuggestionsFromResults(metrics){const out=[],cid=metrics.companyId,sid=metrics.surveyId;const due=d=>datePlus(d);(metrics.dimensions||[]).filter(d=>Number(d.normalized5)<2.5).forEach(d=>out.push(normalizeActionPlan({companyId:cid,surveyId:sid,dimensionId:d.id,dimensionName:d.label,title:`Fortalecer a dimensão ${d.label}`,description:`A dimensão ${d.label} apresentou resultado abaixo do nível esperado. Recomenda-se revisar papéis, responsabilidades e ritos de acompanhamento.`,source:'dimension_critical',priority:'high',dueDate:due(30)})));if(Number(metrics.responseRate)<40&&Number(metrics.sent)>0)out.push(normalizeActionPlan({companyId:cid,surveyId:sid,title:'Aumentar adesão à pesquisa',description:'A taxa de resposta está abaixo de 40%. Recomenda-se reforçar comunicação interna e reenviar convites aos participantes pendentes.',source:'survey_result',priority:'medium',dueDate:due(7)}));if(Number(metrics.pendingInvites)>5)out.push(normalizeActionPlan({companyId:cid,surveyId:sid,title:'Reduzir convites pendentes',description:'Há muitos convites pendentes. Recomenda-se reenviar lembretes e acionar gestores de área.',source:'survey_result',priority:'medium',dueDate:due(7)}));if((metrics.qualitativeCritical||0)>0)out.push(normalizeActionPlan({companyId:cid,surveyId:sid,title:'Analisar comentários qualitativos críticos',description:'Foram identificados comentários recorrentes com percepção negativa. Recomenda-se reunião de escuta com os grupos envolvidos.',source:'survey_result',priority:'high',dueDate:due(15)}));if((metrics.nearPlanLimit||false))out.push(normalizeActionPlan({companyId:cid,title:'Revisar limite do plano contratado',description:'O uso está próximo do limite do plano. Recomenda-se avaliar upgrade ou ajuste operacional.',source:'consultant_recommendation',priority:'medium',dueDate:due(15)}));return out;}
function generateActionPlans(){const u=currentUser(),cid=GLOBAL_ROLES.includes(u?.role)?($('#actionCompany')?.value||state.companies[0]?.id):u.companyId;if(!canManageActionPlan(u,cid))return toast(PERMISSION_DENIED_MESSAGE,'error');const resp=window.ValoraAnalytics.getResponseMetrics(state,{companyId:cid}),inv=window.ValoraAnalytics.getInvitationMetrics(state,cid),usage=window.ValoraAnalytics.getPlanUsageMetrics(state,cid);const suggestions=generateActionSuggestionsFromResults({companyId:cid,dimensions:resp.dimensions,responseRate:inv.responseRate,sent:inv.sent,pendingInvites:state.invitations.filter(i=>i.companyId===cid&&i.status!=='answered').length,nearPlanLimit:usage.items?.some(i=>i.nearLimit)}).filter(s=>!state.actionPlans.some(a=>a.companyId===s.companyId&&a.title===s.title));suggestions.forEach(a=>{a.id=uid('act');a.createdBy=u.id;a.updatedBy=u.id;state.actionPlans.push(a);audit('Ação gerada automaticamente','actionPlan',a.id,a.title);});persist(`${suggestions.length} ação(ões) sugerida(s) criada(s).`);rerenderPortal();}
function filterActionPlans(){const pr=$('#actionPriority')?.value||'',st=$('#actionStatus')?.value||'',di=($('#actionDimension')?.value||'').toLowerCase(),re=($('#actionResponsible')?.value||'').toLowerCase(),de=($('#actionDepartment')?.value||'').toLowerCase(),so=$('#actionSource')?.value||'';$$('[data-action-plan-row]').forEach(r=>{r.style.display=(!pr||r.dataset.priority===pr)&&(!st||r.dataset.status===st)&&(!di||r.dataset.dimension.includes(di))&&(!re||r.dataset.responsible.includes(re))&&(!de||r.dataset.department.includes(de))&&(!so||r.dataset.source===so)?'':'none';});}
function seedActionPlans(companyId,surveyId,form){return [normalizeActionPlan({id:'act_demo_1',companyId,surveyId,dimensionId:'governanca',dimensionName:'Gestão e Governança',title:'Fortalecer governança de indicadores',description:'Revisar ritos mensais, responsáveis e indicadores-chave da operação.',source:'dimension_critical',priority:'high',status:'in_progress',responsibleUserId:'u_rh',responsibleName:'RH Empresa Exemplo',department:'RH',dueDate:datePlus(30),progress:35,createdBy:'system'}),normalizeActionPlan({id:'act_demo_2',companyId,surveyId,dimensionName:'Pessoas e Talentos',title:'Registrar evidências de desenvolvimento',description:'Centralizar evidências das ações de desenvolvimento e feedback.',source:'manual',priority:'medium',status:'pending',department:'RH',dueDate:datePlus(15),progress:0,createdBy:'system'})];}

function reportsSection(scope){
  const user=currentUser(), company=currentCompany(), admin=scope==='admin';
  if(!admin&&!company)return '<div class="danger-box">Empresa não encontrada.</div>';
  if(!admin&&!can(user,'canViewReports'))return `<div class="danger-box">${PERMISSION_DENIED_MESSAGE}</div>`;
  const types=admin?[['global','Executivo global'],['onboarding','Implantação por cliente'],['plan','Uso do plano por cliente']]:[['company','Executivo da empresa'],['survey','Por pesquisa'],['dimension','Por dimensão'],['onboarding','Implantação'],['plan','Uso do plano']];
  const companyOptions=(admin?state.companies:[company]).filter(Boolean).map(c=>`<option value="${esc(c.id)}">${esc(c.name)}</option>`).join('');
  const surveyOptions=scopedSurveys(admin?state.companies[0]?.id:company.id).map(s=>`<option value="${esc(s.id)}">${esc(s.title)}</option>`).join('');
  const preview=buildReportForScope(scope,'preview');
  return `<div class="kpi-grid">${kpi('Tipos executivos',types.length,'Global, empresa, pesquisa e uso')}${kpi('Formatos','PDF • Word • Excel • CSV • JSON','Exportação padronizada')}${kpi('Privacidade','Ativa','Escopo por perfil/empresa')}${kpi('Resumo automático','Disponível','Recomendações e plano de ação')}</div><div class="card"><h3>Central de relatórios executivos</h3><p>Escolha o tipo de relatório, revise o preview e exporte. Os indicadores vêm do analytics-service para manter consistência com dashboards.</p><div class="form-grid"><div class="field"><label>Tipo de relatório</label><select id="reportType">${types.map(([id,label])=>`<option value="${id}">${esc(label)}</option>`).join('')}</select></div><div class="field"><label>Empresa</label><select id="reportCompany" ${admin?'':'disabled'}>${companyOptions}</select></div><div class="field"><label>Pesquisa</label><select id="reportSurvey">${surveyOptions||'<option value="">Sem pesquisa disponível</option>'}</select></div><div class="field"><label>Dimensão</label><input id="reportDimension" placeholder="Nome da dimensão"></div><div class="field"><label>De</label><input id="reportFrom" type="date"></div><div class="field"><label>Até</label><input id="reportTo" type="date"></div></div><div class="table-actions"><button class="btn btn-primary" data-action="exportExecutiveReport" data-scope="${scope}" data-format="pdf">PDF</button><button class="btn btn-secondary" data-action="exportExecutiveReport" data-scope="${scope}" data-format="word">Word</button><button class="btn btn-secondary" data-action="exportExecutiveReport" data-scope="${scope}" data-format="excel">Excel</button><button class="btn btn-soft" data-action="exportExecutiveReport" data-scope="${scope}" data-format="csv">CSV</button><button class="btn btn-soft" data-action="exportExecutiveReport" data-scope="${scope}" data-format="json">JSON</button></div></div><div class="card"><h3>Preview executivo</h3><p><b>${esc(preview.title)}</b><br>${esc(preview.subtitle||'')}</p><div class="notice">${esc(preview.summary||'Ainda não há respostas suficientes para gerar análise executiva.')}</div>${(preview.recommendations||[]).map(x=>`<p>• ${esc(x)}</p>`).join('')||'<p class="muted">Sem recomendações automáticas no momento.</p>'}</div><div class="card"><h3>Dados do escopo</h3>${miniResponsesTable(admin?state.responses:scopedResponses(company.id),false,scope)}</div>`;
}
function reportFiltersFromUi(){return {from:$('#reportFrom')?.value||'',to:$('#reportTo')?.value||''};}
function buildReportForScope(scope,mode='ui'){
  const companyId=($('#reportCompany')?.value)||(scope==='admin'?state.companies[0]?.id:currentCompany()?.id);
  const type=($('#reportType')?.value)||(scope==='admin'?'global':'company');
  const surveyId=($('#reportSurvey')?.value)||scopedSurveys(companyId)[0]?.id;
  const dimensionId=($('#reportDimension')?.value)||'';
  const filters=mode==='preview'?{}:reportFiltersFromUi();
  if(type==='global'&&scope==='admin')return window.ValoraReports.buildGlobalExecutiveReport(state,filters);
  if(type==='survey')return window.ValoraReports.buildSurveyReport(state,surveyId,filters);
  if(type==='dimension')return window.ValoraReports.buildDimensionReport(state,companyId,dimensionId,filters);
  if(type==='onboarding')return window.ValoraReports.buildOnboardingReport(state,companyId);
  if(type==='plan')return window.ValoraReports.buildPlanUsageReport(state,companyId);
  return window.ValoraReports.buildCompanyExecutiveReport(state,companyId,filters);
}
function flattenReportRows(report){
  const out=[];Object.entries(report.metrics||{}).forEach(([k,v])=>out.push({section:'Resumo',item:k,value:typeof v==='object'?JSON.stringify(v):v}));
  (report.sections?.dimensions||[]).forEach(d=>out.push({section:'Dimensões',item:d.label,value:Number(d.normalized5||0).toFixed(2),percent:Math.round(d.percentage||0)+'%'}));
  (report.actionPlan||[]).forEach(a=>out.push({section:'Plano de ação',item:a.dimension,value:a.action,priority:a.priority,owner:a.owner,due:a.due}));
  (report.sections?.responses||[]).forEach(r=>out.push({section:'Respostas',...r}));
  (report.sections?.ranking||[]).forEach(r=>out.push({section:'Ranking',...r}));
  (report.sections?.usage||[]).forEach(r=>out.push({section:'Uso do plano',item:r.label,value:`${r.used} / ${r.limit<0?'Ilimitado':r.limit}`,percent:(r.percentage||0)+'%'}));
  if(!out.length)out.push({section:'Estado vazio',item:'Mensagem',value:'Ainda não há dados suficientes para este relatório.'});
  return out;
}
