function openInvoiceEditor(id=''){if(currentUser()?.role!=='admin_valora')return toast(PERMISSION_DENIED_MESSAGE,'error');const i=id?state.invoices.find(x=>x.id===id):null;openModal(i?'Editar fatura':'Nova fatura',`<form class="grid" data-form="invoice"><input type="hidden" name="id" value="${esc(i?.id||'')}"><div class="form-grid"><div class="field"><label>Cliente</label><select name="companyId">${state.companies.map(c=>`<option value="${c.id}" ${i?.companyId===c.id?'selected':''}>${esc(c.name)}</option>`).join('')}</select></div><div class="field"><label>Valor</label><input name="amount" type="number" min="0" step="0.01" value="${esc(i?.amount||0)}" required></div><div class="field"><label>Vencimento</label><input name="dueAt" type="date" value="${dateInput(i?.dueAt||datePlus(30))}" required></div><div class="field"><label>Status</label><select name="status"><option value="open" ${i?.status==='open'?'selected':''}>Em aberto</option><option value="paid" ${i?.status==='paid'?'selected':''}>Pago</option><option value="overdue" ${i?.status==='overdue'?'selected':''}>Vencido</option></select></div></div><div class="confirm-actions"><button type="button" class="btn btn-soft" data-action="closeModal">Cancelar</button><button class="btn btn-primary">Salvar fatura</button></div></form>`);}
function saveInvoice(form){const fd=data(form),existing=fd.id?state.invoices.find(x=>x.id===fd.id):null;const payload={companyId:fd.companyId,amount:Number(fd.amount),dueAt:new Date(`${fd.dueAt}T12:00:00`).toISOString(),status:fd.status,updatedAt:nowIso()};if(existing){Object.assign(existing,payload);audit('Fatura editada','fatura',existing.id,companyName(existing.companyId));}else{const i={id:uid('inv'),...payload,createdAt:nowIso()};state.invoices.push(i);audit('Fatura criada','fatura',i.id,companyName(i.companyId));}persist('Fatura salva.');closeModal();rerenderPortal();}
function deleteInvoice(id){const i=state.invoices.find(x=>x.id===id);if(!i)return;confirmAction('Excluir fatura?',`Excluir a fatura de ${money(i.amount)}?`,()=>{state.invoices=state.invoices.filter(x=>x.id!==id);audit('Fatura excluída','fatura',id,companyName(i.companyId));persist('Fatura excluída.');rerenderPortal();});}

function openPlanEditor(id=''){
  if(currentUser()?.role!=='admin_valora')return toast(PERMISSION_DENIED_MESSAGE,'error');
  const p=id?planById(id):{id:'',name:'',price:0,status:'active',default:false,highlight:false,maxActiveSurveys:1,maxResponsesMonth:30,maxManagers:1,maxEmployees:0,description:'',features:['Novo benefício comercial'],enabledModules:defaultEnabledModules({},state.modules),internalNotes:'',allowReports:true,allowCertificates:true,allowEmailSending:true,allowValoraBot:false,allowExport:true,allowCustomQuestionnaires:true,allowGlobalTemplates:false};
  if(id&&!p)return toast('Plano não localizado.','error');
  const clients=id?planCompanies(id).length:0, modules=state.modules||[];
  openModal(id?'Editar plano':'Novo plano',`<form class="grid" data-form="plan"><input type="hidden" name="id" value="${esc(p.id)}">${clients?`<div class="page-help"><b>Atenção:</b> Este plano possui ${clients} cliente(s) vinculado(s). Alterações de preço e limites podem impactar contratos ativos.</div>`:''}<div class="form-grid"><div class="field"><label>Nome</label><input name="name" value="${esc(p.name)}" required spellcheck="true"></div><div class="field"><label>Preço mensal</label><input name="price" type="number" step="0.01" min="0" value="${Number(p.price||0)}" required></div><div class="field"><label>Status</label><select name="status"><option value="active" ${planStatus(p)==='active'?'selected':''}>Ativo</option><option value="inactive" ${planStatus(p)==='inactive'?'selected':''}>Inativo</option></select></div><div class="field"><label>Pesquisas ativas</label><input name="maxActiveSurveys" type="number" min="-1" step="1" value="${Number(p.maxActiveSurveys??0)}"><span class="field-help">Use -1 para ilimitado.</span></div><div class="field"><label>Respostas por mês</label><input name="maxResponsesMonth" type="number" min="0" step="1" value="${Number(p.maxResponsesMonth??0)}"></div><div class="field"><label>Gestores</label><input name="maxManagers" type="number" min="0" step="1" value="${Number(p.maxManagers??0)}"></div><div class="field"><label>Funcionários/respondentes</label><input name="maxEmployees" type="number" min="0" step="1" value="${Number(p.maxEmployees??p.maxRespondents??0)}"><span class="field-help">0 indica sem limite operacional configurado.</span></div><div class="field span-2"><label>Descrição</label><textarea name="description" required spellcheck="true">${esc(p.description)}</textarea></div><div class="field span-2"><label>Recursos comerciais exibidos no card</label><div class="resource-editor" data-plan-features>${planFeatures(p).map((f,i)=>planFeatureRow(f,i)).join('')}</div><button type="button" class="btn btn-soft btn-mini" data-action="addPlanFeature">Adicionar recurso</button><span class="field-help">Use os botões para remover, duplicar ou reordenar. Máximo de 120 caracteres por recurso.</span></div><div class="field span-2"><label>Módulos liberados</label><div class="module-check-grid">${modules.map(m=>`<label class="checkline"><input type="checkbox" name="enabledModules" value="${esc(m.id)}" ${planModules(p).includes(m.id)?'checked':''}><span>${esc(m.name)}</span></label>`).join('')}</div></div><div class="field span-2"><label>Observações internas</label><textarea name="internalNotes" spellcheck="true">${esc(p.internalNotes||'')}</textarea></div></div><div class="grid grid-2"><label class="checkline"><input name="default" type="checkbox" ${p.default?'checked':''}><span>Plano padrão para novos ambientes</span></label><label class="checkline"><input name="highlight" type="checkbox" ${p.highlight?'checked':''}><span>Plano em destaque principal</span></label>${[['allowReports','Permite relatórios'],['allowCertificates','Permite certificados'],['allowEmailSending','Permite envio por e-mail'],['allowValoraBot','Permite ValoraBot'],['allowExport','Permite exportação'],['allowCustomQuestionnaires','Permite questionários personalizados'],['allowGlobalTemplates','Permite templates globais']].map(([k,l])=>`<label class="checkline"><input name="${k}" type="checkbox" ${p[k]!==false?'checked':''}><span>${l}</span></label>`).join('')}</div><div class="card plan-preview"><h3>Prévia do card</h3><p>Salve para ver a prévia completa na listagem com KPIs e clientes vinculados.</p></div><div class="confirm-actions"><button type="button" class="btn btn-soft" data-action="closeModal">Cancelar</button><button class="btn btn-primary">Salvar plano</button></div></form>`,'large');
}
function planFeatureRow(text='',i=0){return `<div class="resource-row"><input name="features" maxlength="120" value="${esc(text)}" placeholder="Ex.: Até 3 pesquisas ativas"><button type="button" class="btn btn-soft btn-mini" data-action="movePlanFeature" data-direction="up">↑</button><button type="button" class="btn btn-soft btn-mini" data-action="movePlanFeature" data-direction="down">↓</button><button type="button" class="btn btn-soft btn-mini" data-action="duplicatePlanFeature">Duplicar</button><button type="button" class="btn btn-danger btn-mini" data-action="removePlanFeature">Remover</button></div>`;}
function collectPlanFeatures(form){return $$('input[name="features"]',form).map(i=>i.value.trim()).filter(Boolean);}
function addPlanFeature(el){const box=el.closest('form').querySelector('[data-plan-features]');box.insertAdjacentHTML('beforeend',planFeatureRow(''));}
function removePlanFeature(el){el.closest('.resource-row')?.remove();}
function duplicatePlanFeature(el){const row=el.closest('.resource-row');row.insertAdjacentHTML('afterend',planFeatureRow($('input',row)?.value||''));}
function movePlanFeature(el){const row=el.closest('.resource-row'),dir=el.dataset.direction;if(!row)return;const sib=dir==='up'?row.previousElementSibling:row.nextElementSibling;if(!sib)return;if(dir==='up')row.parentNode.insertBefore(row,sib);else row.parentNode.insertBefore(sib,row);}
function validatePlanPayload(payload,id){if(!payload.name)return 'Informe o nome do plano.';if(!payload.description)return 'Informe a descrição do plano.';if(Number(payload.price)<0||Number.isNaN(Number(payload.price)))return 'Preço deve ser número maior ou igual a zero.';for(const k of ['maxActiveSurveys','maxResponsesMonth','maxManagers','maxEmployees']){const n=Number(payload[k]);if(!Number.isInteger(n)||n< (k==='maxActiveSurveys'?-1:0))return 'Limites devem ser números inteiros maiores ou iguais a zero. Apenas pesquisas ativas aceita -1 para ilimitado.';}if(!payload.features.length)return 'Informe pelo menos um recurso/benefício.';if(payload.features.some(f=>f.length>120))return 'Cada recurso deve ter no máximo 120 caracteres.';if(state.plans.some(p=>p.id!==id&&p.name.trim().toLowerCase()===payload.name.trim().toLowerCase()))return 'Já existe um plano com este nome.';if(payload.default&&payload.status!=='active')return 'Não é permitido definir plano inativo como padrão.';if(payload.highlight&&payload.status!=='active')return 'Não é permitido destacar plano inativo.';return '';}
function savePlan(form){
  if(!can(currentUser(),'canManagePlans'))return toast(PERMISSION_DENIED_MESSAGE,'error');
  const fd=data(form),existing=fd.id?planById(fd.id):null,features=collectPlanFeatures(form),enabledModules=Array.isArray(fd.enabledModules)?fd.enabledModules:(fd.enabledModules?[fd.enabledModules]:[]);
  const payload={name:(fd.name||'').trim(),price:Number(fd.price||0),status:fd.status||'active',maxActiveSurveys:Number(fd.maxActiveSurveys),maxResponsesMonth:Number(fd.maxResponsesMonth),maxManagers:Number(fd.maxManagers),maxEmployees:Number(fd.maxEmployees||0),description:(fd.description||'').trim(),features,enabledModules,internalNotes:fd.internalNotes||'',default:!!fd.default,highlight:!!fd.highlight,allowReports:!!fd.allowReports,allowCertificates:!!fd.allowCertificates,allowEmailSending:!!fd.allowEmailSending,allowValoraBot:!!fd.allowValoraBot,allowExport:!!fd.allowExport,allowCustomQuestionnaires:!!fd.allowCustomQuestionnaires,allowGlobalTemplates:!!fd.allowGlobalTemplates,updatedAt:nowIso()};
  const err=validatePlanPayload(payload,fd.id);if(err)return toast(err,'error');
  if(payload.default)state.plans.forEach(x=>x.default=false);if(payload.highlight)state.plans.forEach(x=>x.highlight=false);
  if(existing){const before=deepClone(existing);Object.assign(existing,payload);audit('Plano atualizado','plano',existing.id,`${existing.name} • alterado por ${currentUser()?.email||'sistema'} • antes=${JSON.stringify(before).slice(0,800)}`);persist('Plano atualizado.');}
  else{const p={id:uid('plan'),...payload,createdAt:nowIso()};state.plans.push(p);audit('Plano criado','plano',p.id,p.name);persist('Plano criado.');}
  closeModal();rerenderPortal();
}
function duplicatePlan(id){const p=planById(id);if(!p)return;const copy={...deepClone(p),id:uid('plan'),name:`Cópia de ${p.name}`,default:false,highlight:false,status:'inactive',createdAt:nowIso(),updatedAt:nowIso()};state.plans.push(copy);audit('Plano duplicado','plano',copy.id,copy.name);persist('Plano duplicado. Revise os dados antes de ativar.');rerenderPortal();}
function setDefaultPlan(id){const p=planById(id);if(!p)return;if(planStatus(p)!=='active')return toast('Não é permitido definir plano inativo como padrão.','error');confirmAction('Definir plano padrão?', 'Deseja definir este plano como padrão para novos ambientes?',()=>{state.plans.forEach(x=>x.default=x.id===id);audit('Plano padrão definido','plano',p.id,p.name);persist('Plano padrão atualizado.');rerenderPortal();},false);}
function togglePlanHighlight(id){const p=planById(id);if(!p)return;if(!p.highlight&&planStatus(p)!=='active')return toast('Não é permitido destacar plano inativo.','error');state.plans.forEach(x=>{if(x.id!==id)x.highlight=false;});p.highlight=!p.highlight;audit(p.highlight?'Plano destacado':'Destaque removido','plano',p.id,p.name);persist('Destaque comercial atualizado.');rerenderPortal();}
function togglePlanStatus(id){const p=planById(id);if(!p)return;if(p.default&&planStatus(p)==='active')return toast('Não é permitido inativar o plano padrão.','error');p.status=planStatus(p)==='active'?'inactive':'active';if(p.status==='inactive')p.highlight=false;audit(p.status==='active'?'Plano ativado':'Plano inativado','plano',p.id,p.name);persist('Status do plano atualizado.');rerenderPortal();}
function deletePlan(id){const p=planById(id);if(!p)return;if(planCompanies(id).length)return toast('Este plano possui clientes vinculados e não pode ser excluído. Migre os clientes para outro plano antes.','error');confirmAction('Excluir plano?',`Excluir “${p.name}”?`,()=>{state.plans=state.plans.filter(x=>x.id!==id);audit('Plano excluído','plano',id,p.name);persist('Plano excluído.');rerenderPortal();});}

function openModuleEditor(id){const m=state.modules.find(x=>x.id===id);if(!m||currentUser()?.role!=='admin_valora')return;openModal('Editar módulo',`<form class="grid" data-form="module"><input type="hidden" name="id" value="${m.id}"><div class="field"><label>Nome</label><input name="name" value="${esc(m.name)}"></div><div class="field"><label>Descrição</label><textarea name="description">${esc(m.description)}</textarea></div><div class="field"><label>Funcionalidades</label><textarea name="features">${esc(m.features)}</textarea></div><button class="btn btn-primary">Salvar módulo</button></form>`);}
function saveModule(form){if(!can(currentUser(),'canManageModules'))return toast(PERMISSION_DENIED_MESSAGE,'error');const fd=data(form),m=state.modules.find(x=>x.id===fd.id);if(!m)return;Object.assign(m,{name:fd.name,description:fd.description,features:fd.features});audit('Módulo editado','módulo',m.id,m.name);persist('Módulo salvo.');closeModal();rerenderPortal();}
function toggleModule(id,enabled){const m=state.modules.find(x=>x.id===id);if(!m||!can(currentUser(),'canManageModules'))return toast(PERMISSION_DENIED_MESSAGE,'error');confirmAction(`${enabled?'Ativar':'Desativar'} módulo?`,`${enabled?'Ativar':'Desativar'} ${m.name}?`,()=>{m.enabled=enabled;audit(enabled?'Módulo ativado':'Módulo desativado','módulo',m.id,m.name);persist(`Módulo ${enabled?'ativado':'desativado'}.`);rerenderPortal();},false,()=>rerenderPortal());}

function blankQuestion(type='scale',dimension=null){
  const q={id:uid('q'),text:'',help:'',dimensionId:dimension?.id||'',dimensionName:dimension?.name||'Geral',type,required:true,weight:1,maxScore:type==='scale'?5:1,scoreWhenFilled:0,spellcheck:true,options:[]};
  if(['single','multiple','singleCorrect'].includes(type))q.options=[{id:uid('opt'),text:'Opção 1',score:type==='singleCorrect'?1:0,correct:type==='singleCorrect'},{id:uid('opt'),text:'Opção 2',score:0,correct:false}];
  return q;
}
function normalizeForm(form){
  const f=deepClone(form||{});f.id=f.id||'';f.name=f.name||'';f.category=f.category||'Personalizado';f.description=f.description||'';f.timeMin=Number(f.timeMin||5);f.status=f.status||'active';f.scoringMethod=f.scoringMethod||'weightedAverage';f.dimensions=Array.isArray(f.dimensions)&&f.dimensions.length?f.dimensions:[{id:uid('dim'),name:'Geral',description:'Perguntas gerais'}];f.questions=Array.isArray(f.questions)?f.questions:[];f.resultBands=Array.isArray(f.resultBands)&&f.resultBands.length?f.resultBands:defaultBands();f.questions=f.questions.map(q=>normalizeQuestion(q,f.dimensions));return f;
}
function normalizeQuestion(q,dimensions){
  const type=QUESTION_TYPES[q.type]?q.type:({radio:'single',checkbox:'multiple',text:'longText'}[q.type]||'scale');const dim=dimensions.find(d=>d.id===q.dimensionId)||dimensions[0];const out={id:q.id||uid('q'),text:q.text||'',help:q.help||'',dimensionId:dim?.id||'',dimensionName:dim?.name||'Geral',type,required:q.required!==false,weight:Number(q.weight||1),maxScore:Number(q.maxScore??(type==='scale'?5:1)),scoreWhenFilled:Number(q.scoreWhenFilled||0),spellcheck:q.spellcheck!==false,options:Array.isArray(q.options)?q.options.map(o=>({id:o.id||uid('opt'),text:o.text||'',score:Number(o.score||0),correct:!!o.correct})):[]};
  if(['single','multiple','singleCorrect'].includes(type)&&out.options.length<2)out.options=[{id:uid('opt'),text:'Opção 1',score:type==='singleCorrect'?out.maxScore:0,correct:type==='singleCorrect'},{id:uid('opt'),text:'Opção 2',score:0,correct:false}];
  if(type==='singleCorrect'&&!out.options.some(o=>o.correct))out.options[0].correct=true;return out;
}
function openFormEditor(id=''){
  const actor=currentUser();if(!actor||!['admin_valora','empresa_admin','gestor_pesquisa'].includes(actor.role))return toast('Seu perfil não pode criar formulários.','error');
  let source=id?formById(id):null;if(id&&!source)return toast('Formulário não localizado.','error');
  if(source?.global&&actor.role!=='admin_valora'){source=deepClone(source);source.id='';source.global=false;source.companyId=actor.companyId;source.name=`Cópia de ${source.name}`;source.createdAt='';}
  builderDraft=normalizeForm(source||{global:actor.role==='admin_valora',companyId:actor.role==='admin_valora'?'':actor.companyId,name:'Novo formulário',category:'Personalizado',description:'',timeMin:5,scoringMethod:'weightedAverage'});
  openModal(builderDraft.id?'Editar formulário':'Criar novo formulário','<div id="builderRoot"></div>','large');renderBuilder();
}
function renderBuilder(){
  const root=$('#builderRoot');if(!root||!builderDraft)return;const f=builderDraft;
  root.innerHTML=`<div class="builder-intro"><div><span class="badge">Editor dinâmico</span><h3>${esc(f.name||'Novo formulário')}</h3><p>Crie uma pesquisa ou prova. Cada pergunta escolhe seu próprio componente: escala, radio button, checkbox, text box, text area ou resposta correta.</p></div><div class="table-actions"><button class="btn btn-soft" data-action="reviewBuilder">Revisar texto e estrutura</button><button class="btn btn-secondary" data-action="previewBuilder">Pré-visualizar</button><button class="btn btn-primary" data-action="saveBuilder">Salvar formulário</button></div></div>
  <div class="card builder-meta"><h3>1. Configuração do formulário</h3><div class="form-grid"><div class="field span-2"><label>Nome</label><input id="b_name" value="${esc(f.name)}" spellcheck="true" required></div><div class="field"><label>Categoria</label><input id="b_category" value="${esc(f.category)}" spellcheck="true"></div><div class="field"><label>Tempo estimado</label><div class="input-suffix"><input id="b_time" type="number" min="1" max="120" value="${Number(f.timeMin||5)}"><span>min</span></div></div><div class="field span-2"><label>Descrição</label><textarea id="b_description" spellcheck="true">${esc(f.description)}</textarea></div><div class="field"><label>Método de cálculo</label><select id="b_scoring"><option value="weightedAverage" ${f.scoringMethod==='weightedAverage'?'selected':''}>Média ponderada normalizada (0 a 5)</option><option value="average" ${f.scoringMethod==='average'?'selected':''}>Média simples normalizada (0 a 5)</option><option value="sum" ${f.scoringMethod==='sum'?'selected':''}>Soma das notas (com equivalente 0 a 5)</option></select></div><div class="field"><label>Status do modelo</label><select id="b_status"><option value="active" ${f.status!=='inactive'?'selected':''}>Ativo</option><option value="inactive" ${f.status==='inactive'?'selected':''}>Inativo</option></select></div></div><div class="type-legend"><b>Tipos disponíveis:</b>${Object.values(QUESTION_TYPES).map(t=>`<span><strong>${esc(t.label)}</strong> — ${esc(t.control)}</span>`).join('')}</div></div>
  <div class="card"><div class="builder-toolbar"><div><h3>2. Dimensões</h3><p class="muted">Agrupam perguntas e alimentam os KPIs por tema.</p></div><button class="btn btn-secondary" data-action="addDimension">Adicionar dimensão</button></div><div class="dimension-editor">${f.dimensions.map((d,i)=>dimensionEditor(d,i)).join('')}</div></div>
  <div class="card"><div class="builder-toolbar"><div><h3>3. Perguntas</h3><p class="muted">Escolha um tipo ao adicionar ou altere dentro de cada cartão.</p></div><button class="btn btn-primary" data-action="addQuestion" data-type="scale">Adicionar pergunta</button></div><div class="builder-add-types">${Object.entries(QUESTION_TYPES).map(([key,t])=>`<button class="type-add-button" data-action="addQuestion" data-type="${key}"><b>${esc(t.label)}</b><span>${esc(t.control)}</span></button>`).join('')}</div><div class="question-editor" id="questionEditor">${f.questions.map((q,i)=>questionEditor(q,i)).join('')||'<div class="empty">Adicione a primeira pergunta usando um dos tipos acima.</div>'}</div></div>
  <div class="card"><div class="builder-toolbar"><div><h3>4. Faixas de resultado</h3><p class="muted">As faixas usam o índice normalizado de 0 a 5, mesmo quando o método principal é soma.</p></div><button class="btn btn-secondary" data-action="addBand">Adicionar faixa</button></div><div class="band-editor">${f.resultBands.map((b,i)=>bandEditor(b,i)).join('')}</div></div>
  <div id="builderReview"></div><div class="sticky-builder-actions"><button class="btn btn-soft" data-action="closeModal">Cancelar</button><button class="btn btn-secondary" data-action="previewBuilder">Pré-visualizar</button><button class="btn btn-primary" data-action="saveBuilder">Salvar formulário</button></div>`;
}
function dimensionEditor(d,i){return `<div class="dimension-card" data-dim-id="${d.id}"><div class="form-grid"><div class="field"><label>Dimensão ${i+1}</label><input data-dim-field="name" value="${esc(d.name)}" spellcheck="true"></div><div class="field"><label>Descrição</label><input data-dim-field="description" value="${esc(d.description||'')}" spellcheck="true"></div></div><button class="btn btn-danger btn-mini" data-action="removeDimension" data-id="${d.id}" ${builderDraft.dimensions.length===1?'disabled':''}>Remover</button></div>`;}
function questionEditor(q,i){
  const meta=QUESTION_TYPES[q.type];const optionTypes=['single','multiple','singleCorrect'].includes(q.type);const textType=['shortText','longText'].includes(q.type);
  return `<article class="question-card" data-q-id="${q.id}"><div class="question-top"><div class="question-title-row"><span class="question-number">${i+1}</span><div><b>${esc(meta.label)}</b><small>${esc(meta.control)}</small></div></div><div class="question-actions"><button class="btn btn-soft btn-mini" data-action="moveQuestion" data-id="${q.id}" data-direction="up" ${i===0?'disabled':''}>↑</button><button class="btn btn-soft btn-mini" data-action="moveQuestion" data-id="${q.id}" data-direction="down" ${i===builderDraft.questions.length-1?'disabled':''}>↓</button><button class="btn btn-secondary btn-mini" data-action="duplicateQuestion" data-id="${q.id}">Duplicar</button><button class="btn btn-danger btn-mini" data-action="removeQuestion" data-id="${q.id}">Remover</button></div></div>
  <div class="field"><label>Texto da pergunta</label>${q.type==='longText'?`<textarea data-q-field="text" spellcheck="true" placeholder="Digite a pergunta">${esc(q.text)}</textarea>`:`<input data-q-field="text" value="${esc(q.text)}" spellcheck="true" placeholder="Digite a pergunta">`}</div>
  <div class="form-grid"><div class="field"><label>Dimensão</label><select data-q-field="dimensionId">${builderDraft.dimensions.map(d=>`<option value="${d.id}" ${q.dimensionId===d.id?'selected':''}>${esc(d.name)}</option>`).join('')}</select></div><div class="field"><label>Tipo de resposta</label><select data-q-field="type" data-change="questionType" data-id="${q.id}">${Object.entries(QUESTION_TYPES).map(([key,t])=>`<option value="${key}" ${q.type===key?'selected':''}>${esc(t.label)} — ${esc(t.control)}</option>`).join('')}</select></div><div class="field"><label>Peso</label><input data-q-field="weight" type="number" min="0" step="0.1" value="${Number(q.weight||1)}"></div><div class="field"><label>Pontuação máxima</label><input data-q-field="maxScore" type="number" min="0" step="0.1" value="${Number(q.maxScore||0)}"></div>${textType?`<div class="field"><label>Nota quando preenchida</label><input data-q-field="scoreWhenFilled" type="number" min="0" step="0.1" value="${Number(q.scoreWhenFilled||0)}"></div>`:''}<div class="field span-2"><label>Ajuda opcional ao participante</label><input data-q-field="help" value="${esc(q.help||'')}" spellcheck="true"></div></div>
  <label class="checkline"><input data-q-field="required" type="checkbox" ${q.required?'checked':''}><span>Resposta obrigatória</span></label>
  <div class="type-explain"><b>${esc(meta.label)} (${esc(meta.control)}).</b> ${esc(meta.help)}</div>
  ${optionTypes?`<div class="option-list"><div class="builder-toolbar"><b>Alternativas e pontuação</b><button class="btn btn-soft btn-mini" data-action="addOption" data-id="${q.id}">Adicionar alternativa</button></div>${q.options.map((o,j)=>optionEditor(q,o,j)).join('')}</div>`:''}
  <div class="question-preview"><b>Prévia do componente</b>${previewQuestion(q,i,true)}</div></article>`;
}
function optionEditor(q,o,i){return `<div class="option-row" data-option-id="${o.id}"><div class="field"><label>Alternativa ${i+1}</label><input data-option-field="text" value="${esc(o.text)}" spellcheck="true"></div><div class="field"><label>Pontos</label><input data-option-field="score" type="number" step="0.1" value="${Number(o.score||0)}"></div>${q.type==='singleCorrect'?`<label class="checkline compact-check"><input type="radio" name="correct_${q.id}" data-option-field="correct" ${o.correct?'checked':''}><span>Correta</span></label>`:'<div></div>'}<button class="btn btn-danger btn-mini" data-action="removeOption" data-qid="${q.id}" data-id="${o.id}" ${q.options.length<=2?'disabled':''}>Remover</button></div>`;}
function bandEditor(b,i){return `<div class="band-card" data-band-index="${i}"><div class="form-grid"><div class="field"><label>Nível</label><input data-band-field="label" value="${esc(b.label)}" spellcheck="true"></div><div class="field"><label>De</label><input data-band-field="from" type="number" min="0" max="5" step="0.01" value="${Number(b.from)}"></div><div class="field"><label>Até</label><input data-band-field="to" type="number" min="0" max="5" step="0.01" value="${Number(b.to)}"></div><div class="field"><label>Cor</label><input data-band-field="color" type="color" value="${esc(b.color||'#0b3d4d')}"></div><div class="field span-2"><label>Significado</label><input data-band-field="description" value="${esc(b.description||'')}" spellcheck="true"></div><div class="field span-2"><label>Recomendação</label><textarea data-band-field="recommendation" spellcheck="true">${esc(b.recommendation||'')}</textarea></div></div><button class="btn btn-danger btn-mini" data-action="removeBand" data-index="${i}" ${builderDraft.resultBands.length<=1?'disabled':''}>Remover faixa</button></div>`;}
function collectBuilder(){
  const root=$('#builderRoot');if(!root||!builderDraft)return;
  builderDraft.name=$('#b_name',root)?.value.trim()||builderDraft.name;builderDraft.category=$('#b_category',root)?.value.trim()||'Personalizado';builderDraft.timeMin=Number($('#b_time',root)?.value||5);builderDraft.description=$('#b_description',root)?.value.trim()||'';builderDraft.scoringMethod=$('#b_scoring',root)?.value||'weightedAverage';builderDraft.status=$('#b_status',root)?.value||'active';
  builderDraft.dimensions=$$('.dimension-card',root).map(card=>({id:card.dataset.dimId,name:$('[data-dim-field="name"]',card)?.value.trim()||'Sem nome',description:$('[data-dim-field="description"]',card)?.value.trim()||''}));
  const dimMap=Object.fromEntries(builderDraft.dimensions.map(d=>[d.id,d]));
  builderDraft.questions=$$('.question-card',root).map(card=>{
    const old=builderDraft.questions.find(q=>q.id===card.dataset.qId)||blankQuestion('scale',builderDraft.dimensions[0]);const type=$('[data-q-field="type"]',card)?.value||old.type;const q={...old,id:card.dataset.qId,text:$('[data-q-field="text"]',card)?.value.trim()||'',help:$('[data-q-field="help"]',card)?.value.trim()||'',dimensionId:$('[data-q-field="dimensionId"]',card)?.value||builderDraft.dimensions[0]?.id||'',type,weight:Number($('[data-q-field="weight"]',card)?.value||1),maxScore:Number($('[data-q-field="maxScore"]',card)?.value||0),scoreWhenFilled:Number($('[data-q-field="scoreWhenFilled"]',card)?.value||0),required:!!$('[data-q-field="required"]',card)?.checked};q.dimensionName=dimMap[q.dimensionId]?.name||'Geral';
    if(['single','multiple','singleCorrect'].includes(type))q.options=$$('.option-row',card).map(row=>({id:row.dataset.optionId,text:$('[data-option-field="text"]',row)?.value.trim()||'',score:Number($('[data-option-field="score"]',row)?.value||0),correct:!!$('[data-option-field="correct"]',row)?.checked}));else q.options=[];
    return normalizeQuestion(q,builderDraft.dimensions);
  });
  builderDraft.resultBands=$$('.band-card',root).map(card=>({id:builderDraft.resultBands[Number(card.dataset.bandIndex)]?.id||uid('band'),label:$('[data-band-field="label"]',card)?.value.trim()||'Nível',from:Number($('[data-band-field="from"]',card)?.value||0),to:Number($('[data-band-field="to"]',card)?.value||5),color:$('[data-band-field="color"]',card)?.value||'#0b3d4d',description:$('[data-band-field="description"]',card)?.value.trim()||'',recommendation:$('[data-band-field="recommendation"]',card)?.value.trim()||''}));
}
function validateBuilder(){
  const errors=[],warnings=[];if(!builderDraft.name.trim())errors.push('Informe o nome do formulário.');if(!builderDraft.questions.length)errors.push('Adicione ao menos uma pergunta.');builderDraft.questions.forEach((q,i)=>{if(!q.text.trim())errors.push(`Pergunta ${i+1}: informe o texto.`);if(q.weight<0)errors.push(`Pergunta ${i+1}: o peso não pode ser negativo.`);if(q.maxScore<0)errors.push(`Pergunta ${i+1}: a pontuação máxima não pode ser negativa.`);if(['single','multiple','singleCorrect'].includes(q.type)){if(q.options.length<2)errors.push(`Pergunta ${i+1}: adicione ao menos duas alternativas.`);if(q.options.some(o=>!o.text.trim()))errors.push(`Pergunta ${i+1}: há alternativa sem texto.`);}if(q.type==='singleCorrect'&&q.options.filter(o=>o.correct).length!==1)errors.push(`Pergunta ${i+1}: marque exatamente uma resposta correta.`);const spelling=spellReview(q.text);warnings.push(...spelling.map(x=>`Pergunta ${i+1}: ${x}`));});
  const sorted=[...builderDraft.resultBands].sort((a,b)=>a.from-b.from);sorted.forEach((b,i)=>{if(b.from>b.to)errors.push(`Faixa “${b.label}”: o início é maior que o fim.`);if(i&&b.from<sorted[i-1].to)warnings.push(`As faixas “${sorted[i-1].label}” e “${b.label}” se sobrepõem.`);});return {errors,warnings};
}
function spellReview(text){const issues=[];const s=String(text||'');if(/\s{2,}/.test(s))issues.push('há espaços duplicados');if(s&&s[0]===s[0].toLowerCase()&&/[a-zá-ú]/i.test(s[0]))issues.push('a frase deveria começar com letra maiúscula');if(s.length>3&&!/[?.!:]$/.test(s))issues.push('considere encerrar com pontuação');const common=[['voce','você'],['nao','não'],['governaca','governança'],['lideranca','liderança'],['organizacao','organização'],['colaboracao','colaboração']];common.forEach(([a,b])=>{if(new RegExp(`\\b${a}\\b`,'i').test(s))issues.push(`revise “${a}” (sugestão: “${b}”)`);});return issues;}
function showBuilderReview(){collectBuilder();const r=validateBuilder();const box=$('#builderReview');box.innerHTML=`<div class="review-panel ${r.errors.length||r.warnings.length?'warn':'ok'}"><h3>${r.errors.length?'Correções necessárias':r.warnings.length?'Revisão recomendada':'Formulário pronto para salvar'}</h3>${r.errors.length?`<b>Erros</b><ul>${r.errors.map(x=>`<li>${esc(x)}</li>`).join('')}</ul>`:''}${r.warnings.length?`<b>Avisos de texto e estrutura</b><ul>${r.warnings.map(x=>`<li>${esc(x)}</li>`).join('')}</ul>`:''}${!r.errors.length&&!r.warnings.length?'<p>Nenhuma inconsistência estrutural ou alerta ortográfico básico foi encontrado. O navegador também mantém o corretor ortográfico ativo nos campos de texto.</p>':''}</div>`;box.scrollIntoView({behavior:'smooth',block:'center'});return r;}
function saveBuilder(){collectBuilder();const check=validateBuilder();if(check.errors.length){showBuilderReview();return toast('Corrija os itens indicados antes de salvar.','error');}const actor=currentUser();const existing=builderDraft.id?formById(builderDraft.id):null;if(existing&&existing.global&&actor.role!=='admin_valora')return toast('Clone o modelo global antes de editar.','error');const payload={...builderDraft,global:existing?existing.global:(actor.role==='admin_valora'&&builderDraft.global!==false),companyId:existing?existing.companyId:(actor.role==='admin_valora'?'':actor.companyId),updatedAt:nowIso()};if(existing){Object.assign(existing,payload);audit('Formulário editado','formulário',existing.id,existing.name);}else{payload.id=uid('form');payload.createdAt=nowIso();state.forms.push(payload);audit('Formulário criado','formulário',payload.id,payload.name);}persist('Formulário salvo com sucesso.');closeModal();rerenderPortal();}
function addQuestion(type='scale'){collectBuilder();builderDraft.questions.push(blankQuestion(type,builderDraft.dimensions[0]));renderBuilder();setTimeout(()=>$$('.question-card').at(-1)?.scrollIntoView({behavior:'smooth',block:'center'}),30);}
function removeQuestion(id){collectBuilder();const q=builderDraft.questions.find(x=>x.id===id);confirmAction('Remover pergunta?',`Remover “${q?.text||'esta pergunta'}”?`,()=>{builderDraft.questions=builderDraft.questions.filter(x=>x.id!==id);renderBuilder();});}
function moveQuestion(id,direction){collectBuilder();const i=builderDraft.questions.findIndex(q=>q.id===id);const j=direction==='up'?i-1:i+1;if(i<0||j<0||j>=builderDraft.questions.length)return;[builderDraft.questions[i],builderDraft.questions[j]]=[builderDraft.questions[j],builderDraft.questions[i]];renderBuilder();}
function duplicateQuestion(id){collectBuilder();const i=builderDraft.questions.findIndex(q=>q.id===id);if(i<0)return;const q=deepClone(builderDraft.questions[i]);q.id=uid('q');q.text=`${q.text} (cópia)`;q.options=q.options.map(o=>({...o,id:uid('opt')}));builderDraft.questions.splice(i+1,0,q);renderBuilder();}
function addDimension(){collectBuilder();const d={id:uid('dim'),name:'Nova dimensão',description:'Descreva o tema'};builderDraft.dimensions.push(d);renderBuilder();}
function removeDimension(id){collectBuilder();if(builderDraft.dimensions.length<=1)return toast('O formulário precisa de ao menos uma dimensão.','warn');const d=builderDraft.dimensions.find(x=>x.id===id);confirmAction('Remover dimensão?',`As perguntas de “${d?.name}” serão movidas para a primeira dimensão.`,()=>{builderDraft.dimensions=builderDraft.dimensions.filter(x=>x.id!==id);const first=builderDraft.dimensions[0];builderDraft.questions.forEach(q=>{if(q.dimensionId===id){q.dimensionId=first.id;q.dimensionName=first.name;}});renderBuilder();});}
function addOption(qid){collectBuilder();const q=builderDraft.questions.find(x=>x.id===qid);if(!q)return;q.options.push({id:uid('opt'),text:`Opção ${q.options.length+1}`,score:0,correct:false});renderBuilder();}
function removeOption(qid,id){collectBuilder();const q=builderDraft.questions.find(x=>x.id===qid);if(!q||q.options.length<=2)return toast('Mantenha ao menos duas alternativas.','warn');q.options=q.options.filter(o=>o.id!==id);if(q.type==='singleCorrect'&&!q.options.some(o=>o.correct))q.options[0].correct=true;renderBuilder();}
function addBand(){collectBuilder();builderDraft.resultBands.push({id:uid('band'),label:'Novo nível',from:0,to:5,color:'#0b3d4d',description:'',recommendation:''});renderBuilder();}
function removeBand(index){collectBuilder();if(builderDraft.resultBands.length<=1)return;builderDraft.resultBands.splice(Number(index),1);renderBuilder();}
function changeQuestionType(id){collectBuilder();const q=builderDraft.questions.find(x=>x.id===id);if(q)Object.assign(q,normalizeQuestion(q,builderDraft.dimensions));renderBuilder();}
function previewBuilder(){collectBuilder();previewFormObject(builderDraft);}
function previewFormObject(f){openModal(`Prévia — ${f.name}`,`<div class="page-help"><b>Prévia do participante:</b> esta tela mostra os controles finais e a lógica de cada pergunta.</div><div class="survey-preview">${f.questions.map((q,i)=>previewQuestion(q,i,false)).join('')}</div><div class="confirm-actions"><button class="btn btn-soft" data-action="closeModal">Fechar</button></div>`,'large');}
function previewQuestion(q,i,compact=false){
  const name=`preview_${q.id}`;let control='';if(q.type==='scale')control=`<div class="scale-row">${[1,2,3,4,5].map(n=>`<label><input type="radio" name="${name}">${n}</label>`).join('')}</div>`;else if(q.type==='single'||q.type==='singleCorrect')control=(q.options||[]).map(o=>`<label class="checkline"><input type="radio" name="${name}"><span>${esc(o.text)}</span></label>`).join('');else if(q.type==='multiple')control=(q.options||[]).map(o=>`<label class="checkline"><input type="checkbox"><span>${esc(o.text)}</span></label>`).join('');else if(q.type==='shortText')control='<input placeholder="Resposta curta">';else control='<textarea placeholder="Resposta longa"></textarea>';
  return `<div class="survey-question ${compact?'compact-preview':''}"><h3>${i+1}. ${esc(q.text||'Pergunta sem texto')} ${q.required?'<span class="required-mark">*</span>':''}</h3>${q.help?`<p class="field-help">${esc(q.help)}</p>`:''}${control}<p class="score-hint">${esc(QUESTION_TYPES[q.type]?.label||q.type)} • peso ${Number(q.weight||1)} • máximo ${Number(q.maxScore||0)} ponto(s)</p></div>`;
}
function cloneForm(id){const f=formById(id);if(!f)return;const actor=currentUser();const copy=deepClone(f);copy.id=uid('form');copy.global=actor.role==='admin_valora'?false:false;copy.companyId=actor.role==='admin_valora'?(f.companyId||''):actor.companyId;copy.name=`Cópia de ${f.name}`;copy.createdAt=nowIso();copy.updatedAt=nowIso();copy.questions.forEach(q=>{q.id=uid('q');q.options=q.options.map(o=>({...o,id:uid('opt')}));});state.forms.push(copy);audit('Formulário clonado','formulário',copy.id,copy.name);persist('Formulário clonado.');rerenderPortal();}
function deleteForm(id){const f=formById(id);if(!f)return;if(f.global&&currentUser()?.role!=='admin_valora')return toast('Modelos globais não podem ser excluídos pela empresa.','error');if(state.surveys.some(s=>s.formId===id))return toast('Este formulário está vinculado a pesquisas. Clone ou encerre as pesquisas antes de excluir.','error');confirmAction('Excluir formulário?',`Excluir “${f.name}” e todas as perguntas?`,()=>{state.forms=state.forms.filter(x=>x.id!==id);audit('Formulário excluído','formulário',id,f.name);persist('Formulário excluído.');rerenderPortal();});}

function openSurveyEditor(id='',presetFormId=''){
  const actor=currentUser();if(!actor||!can(actor,'canCreateSurveys'))return toast(PERMISSION_DENIED_MESSAGE,'error');const s=id?state.surveys.find(x=>x.id===id):null;if(id&&!s)return toast('Pesquisa não localizada.','error');if(s&&!canManageCompany(s.companyId))return toast('Pesquisa fora do seu ambiente.','error');
  const companies=['admin_valora','consultor_valora'].includes(actor.role)?state.companies:[currentCompany()].filter(Boolean);const forms=actor.role==='admin_valora'||actor.role==='consultor_valora'?state.forms.filter(f=>f.status!=='inactive'):scopedForms(actor.companyId).filter(f=>f.status!=='inactive');const companyId=s?.companyId||companies[0]?.id||'';const formId=s?.formId||presetFormId||forms[0]?.id||'';
  openModal(s?'Editar pesquisa':'Nova pesquisa',`<form class="grid" data-form="survey"><input type="hidden" name="id" value="${esc(s?.id||'')}"><div class="page-help"><b>Jornada:</b> escolha o formulário, defina quem se identifica, aceite LGPD, prazo e resultado. Depois de salvar, use Compartilhar para copiar o link ou enviar por WhatsApp/e-mail.</div><div class="form-grid"><div class="field"><label>Empresa</label><select name="companyId">${companies.map(c=>`<option value="${c.id}" ${companyId===c.id?'selected':''}>${esc(c.name)}</option>`).join('')}</select></div><div class="field"><label>Formulário / prova</label><select name="formId">${forms.map(f=>`<option value="${f.id}" ${formId===f.id?'selected':''}>${esc(f.name)}</option>`).join('')}</select></div><div class="field span-2"><label>Título da pesquisa</label><input name="title" value="${esc(s?.title||formById(formId)?.name||'Nova pesquisa Valora Pulse™')}" required spellcheck="true"></div><div class="field span-2"><label>Descrição</label><textarea name="description" spellcheck="true">${esc(s?.description||'Pesquisa direcionada com resultado instantâneo.')}</textarea></div><div class="field"><label>Início</label><input name="startsAt" type="date" value="${dateInput(s?.startsAt||nowIso())}"></div><div class="field"><label>Expira em</label><input name="expiresAt" type="date" value="${dateInput(s?.expiresAt||datePlus(30))}" required></div><div class="field"><label>Atalho de validade</label><select name="quickDays"><option value="">Usar a data escolhida</option><option value="7">7 dias</option><option value="15">15 dias</option><option value="30">30 dias</option><option value="60">60 dias</option><option value="90">90 dias</option></select></div><div class="field"><label>Status</label><select name="status"><option value="active" ${s?.status!=='draft'&&s?.status!=='closed'?'selected':''}>Ativa</option><option value="draft" ${s?.status==='draft'?'selected':''}>Rascunho</option><option value="closed" ${s?.status==='closed'?'selected':''}>Encerrada</option></select></div></div><div class="grid grid-2"><label class="checkline"><input name="requireIdentification" type="checkbox" ${s?.requireIdentification!==false?'checked':''}><span>Exigir identificação do participante</span></label><label class="checkline"><input name="lgpdRequired" type="checkbox" ${s?.lgpdRequired!==false?'checked':''}><span>Exigir aceite do termo LGPD</span></label><label class="checkline"><input name="allowRepeat" type="checkbox" ${s?.allowRepeat!==false?'checked':''}><span>Permitir refazer a pesquisa</span></label><label class="checkline"><input name="showResult" type="checkbox" ${s?.showResult!==false?'checked':''}><span>Mostrar resultado imediatamente</span></label><label class="checkline"><input name="anonymous" type="checkbox" ${s?.anonymous?'checked':''}><span>Exibir somente consolidado para gestores</span></label></div><div class="confirm-actions"><button type="button" class="btn btn-soft" data-action="closeModal">Cancelar</button><button class="btn btn-primary">Salvar pesquisa</button></div></form>`,'large');
}
function saveSurvey(form){
  const fd=data(form),existing=fd.id?state.surveys.find(s=>s.id===fd.id):null;if(!canManageCompany(fd.companyId))return toast('Empresa fora do seu escopo.','error');if(!existing&&!canCreateSurvey(fd.companyId))return toast('O limite de pesquisas ativas do plano foi atingido.','error');const expires=fd.quickDays?datePlus(Number(fd.quickDays)):new Date(`${fd.expiresAt}T23:59:59`).toISOString();const starts=fd.startsAt?new Date(`${fd.startsAt}T00:00:00`).toISOString():nowIso();if(new Date(expires)<=new Date(starts))return toast('A expiração deve ser posterior ao início.','error');const payload={companyId:fd.companyId,formId:fd.formId,title:fd.title,description:fd.description,status:fd.status,startsAt:starts,expiresAt:expires,requireIdentification:!!fd.requireIdentification,lgpdRequired:!!fd.lgpdRequired,allowRepeat:!!fd.allowRepeat,showResult:!!fd.showResult,anonymous:!!fd.anonymous,updatedAt:nowIso()};
  if(existing){Object.assign(existing,payload);audit('Pesquisa editada','pesquisa',existing.id,existing.title);persist('Pesquisa salva.');closeModal();rerenderPortal();}
  else{const s={id:uid('survey'),token:secureToken(),createdAt:nowIso(),...payload};state.surveys.push(s);audit('Pesquisa criada','pesquisa',s.id,s.title);save();closeModal();rerenderPortal();toast('Pesquisa criada. Abrindo compartilhamento…','success');setTimeout(()=>openShareModal(s.id),100);}
}
function openQuickSurvey(presetFormId=''){
  const actor=currentUser();if(!actor||!can(actor,'canCreateSurveys'))return toast(PERMISSION_DENIED_MESSAGE,'error');const companies=actor.role==='admin_valora'?state.companies:[currentCompany()].filter(Boolean);const forms=actor?.role==='admin_valora'||actor?.role==='consultor_valora'?state.forms.filter(f=>f.status!=='inactive'):scopedForms(actor?.companyId).filter(f=>f.status!=='inactive');if(!forms.length)return toast('Crie ou clone um formulário antes de gerar a pesquisa.','warn');
  openModal('Criar e compartilhar pesquisa instantânea',`<form class="grid" data-form="quickSurvey"><div class="page-help"><b>Em um passo:</b> selecione o formulário, título e validade. O sistema cria um token seguro e abre as opções de WhatsApp, e-mail e cópia do link.</div><div class="form-grid"><div class="field"><label>Empresa</label><select name="companyId">${companies.map(c=>`<option value="${c.id}">${esc(c.name)}</option>`).join('')}</select></div><div class="field"><label>Formulário</label><select name="formId">${forms.map(f=>`<option value="${f.id}" ${presetFormId===f.id?'selected':''}>${esc(f.name)}</option>`).join('')}</select></div><div class="field span-2"><label>Título</label><input name="title" value="${esc(formById(presetFormId)?.name||'Valora Insight™ — diagnóstico de maturidade')}" required></div><div class="field"><label>Validade</label><select name="days"><option value="7">7 dias</option><option value="15">15 dias</option><option value="30" selected>30 dias</option><option value="60">60 dias</option><option value="90">90 dias</option></select></div></div><label class="checkline"><input name="requireIdentification" type="checkbox" checked><span>Exigir identificação</span></label><label class="checkline"><input name="lgpdRequired" type="checkbox" checked><span>Exigir aceite LGPD</span></label><label class="checkline"><input name="allowRepeat" type="checkbox" checked><span>Permitir refazer</span></label><div class="confirm-actions"><button type="button" class="btn btn-soft" data-action="closeModal">Cancelar</button><button class="btn btn-success">Criar e compartilhar</button></div></form>`);
}
function saveQuickSurvey(form){const fd=data(form);if(!canCreateSurvey(fd.companyId))return toast('Limite de pesquisas ativas atingido para este plano.','error');const s={id:uid('survey'),companyId:fd.companyId,formId:fd.formId,title:fd.title,description:'Pesquisa criada pelo fluxo instantâneo.',status:'active',startsAt:nowIso(),expiresAt:datePlus(Number(fd.days||30)),requireIdentification:!!fd.requireIdentification,lgpdRequired:!!fd.lgpdRequired,allowRepeat:!!fd.allowRepeat,showResult:true,anonymous:false,token:secureToken(),createdAt:nowIso(),updatedAt:nowIso()};state.surveys.push(s);audit('Pesquisa instantânea criada','pesquisa',s.id,s.title);persist('Pesquisa criada.');closeModal();openShareModal(s.id);}
function deleteSurvey(id){const s=state.surveys.find(x=>x.id===id);if(!s||!canManageCompany(s.companyId))return;confirmAction('Excluir pesquisa?',`Excluir “${s.title}”? As respostas vinculadas permanecerão no histórico.`,()=>{state.surveys=state.surveys.filter(x=>x.id!==id);if(state.settings.featuredSurveyId===id)state.settings.featuredSurveyId='';audit('Pesquisa excluída','pesquisa',id,s.title);persist('Pesquisa excluída.');rerenderPortal();});}
function featureSurvey(id){if(currentUser()?.role!=='admin_valora')return toast('Apenas o administrador geral escolhe o destaque da home.','error');const s=state.surveys.find(x=>x.id===id);if(!s)return;state.settings.featuredSurveyId=id;audit('Pesquisa destacada na home','pesquisa',id,s.title);persist('Pesquisa definida como destaque da página inicial.');rerenderPortal();}
function renewSurvey(id){const s=state.surveys.find(x=>x.id===id);if(!s||!canManageCompany(s.companyId))return;s.token=secureToken();s.expiresAt=datePlus(30);s.status='active';s.updatedAt=nowIso();audit('Token renovado','pesquisa',id,s.title);persist('Token renovado por 30 dias.');openShareModal(id);}
function openShareModal(id){
  const s=state.surveys.find(x=>x.id===id);if(!s||!canManageCompany(s.companyId))return toast('Pesquisa não localizada ou sem permissão.','error');const link=buildSurveyLink(s);lastShareLink=link;const employees=state.users.filter(u=>u.companyId===s.companyId&&u.status!=='inactive'&&u.email);const sent=state.invitations.filter(i=>i.surveyId===s.id&&i.status==='sent').length;
  openModal('Compartilhar pesquisa',`<div class="share-box"><b>Link seguro pronto.</b><br>Validade: ${brDate(s.expiresAt)} • ${surveyIsActive(s)?'Ativo':'Inativo ou expirado'}.</div><div class="field"><label>Link</label><div class="share-link">${esc(link)}</div></div><div class="table-actions"><button class="btn btn-primary" data-action="copyLink" data-link="${esc(link)}">Copiar link</button><a class="btn btn-success" href="https://wa.me/?text=${encodeURIComponent(`Olá! Você recebeu a pesquisa ${s.title} da ${companyName(s.companyId)}. Acesse o link seguro: ${link}`)}" target="_blank" rel="noopener">Enviar por WhatsApp</a><button class="btn btn-secondary" data-action="inviteEmail" data-id="${s.id}">Enviar e-mail personalizado</button><button class="btn btn-primary" data-action="bulkInviteSurvey" data-id="${s.id}">Enviar para funcionários (${employees.length})</button><button class="btn btn-soft" data-action="openLink" data-link="${esc(link)}">Abrir pesquisa</button><button class="btn btn-warning" data-action="renewSurvey" data-id="${s.id}">Renovar token</button></div><div class="page-help"><b>Convites:</b> ${sent} enviado(s). Status controlados: pending, sent, opened, answered, expired e failed. Em modo local, o servidor grava .eml em data/outbox; em Firebase, o envio deve passar por Cloud Functions, sem SMTP no navegador.</div><div class="page-help"><b>Jornada do cliente:</b> o participante abre o link, se identifica como pessoa física ou empresa, informa e-mail e telefone, aceita a LGPD, responde e escolhe se quer receber o resultado por e-mail.</div>`,'large');audit('Compartilhamento aberto','pesquisa',s.id,s.title);
}
function openInviteEmail(id){const s=state.surveys.find(x=>x.id===id);if(!s)return;const link=buildSurveyLink(s);openModal('Enviar convite por e-mail',`<form class="grid" data-form="inviteEmail"><input type="hidden" name="surveyId" value="${s.id}"><div class="form-grid"><div class="field"><label>Nome do destinatário</label><input name="name" value="Participante"></div><div class="field"><label>E-mail</label><input name="email" type="email" required></div><div class="field span-2"><label>Assunto</label><input name="subject" value="${esc(fillTemplate(state.settings.inviteSubject,{pesquisa:s.title,empresa:companyName(s.companyId),link,validade:brDay(s.expiresAt),nome:'Participante'}))}"></div><div class="field span-2"><label>Mensagem</label><textarea name="message" spellcheck="true">${esc(fillTemplate(state.settings.inviteBody,{pesquisa:s.title,empresa:companyName(s.companyId),link,validade:brDay(s.expiresAt),nome:'Participante'}))}</textarea></div></div><div class="email-preview-card">${brandedEmailPreview('Convite para pesquisa',s.title,link)}</div><div class="confirm-actions"><button type="button" class="btn btn-soft" data-action="closeModal">Cancelar</button><button class="btn btn-primary">Enviar e-mail</button></div></form>`,'large');}
function buildSurveyLink(s){const base=location.href.split('?')[0].split('#')[0];const u=new URL(base);u.searchParams.set('survey',s.id);u.searchParams.set('token',s.token);return u.toString();}
function secureToken(){const bytes=new Uint8Array(24);if(window.crypto?.getRandomValues)window.crypto.getRandomValues(bytes);else for(let i=0;i<bytes.length;i++)bytes[i]=Math.floor(Math.random()*256);return Array.from(bytes,b=>b.toString(16).padStart(2,'0')).join('');}

function getCompanyPlan(companyId){return planById(companyById(companyId)?.planId)||null;}
function getPlanUsage(companyId){return {activeSurveys:scopedSurveys(companyId).filter(s=>surveyIsActive(s)).length,responsesMonth:responsesThisMonth(companyId),managers:state.users.filter(u=>u.companyId===companyId&&['empresa_admin','gestor_pesquisa'].includes(u.role)&&u.status==='active').length,employees:state.users.filter(u=>u.companyId===companyId&&COMPANY_ROLES.includes(u.role)&&u.status==='active').length,emailsMonth:state.invitations.filter(i=>i.companyId===companyId&&new Date(i.createdAt||i.sentAt||0).getMonth()===new Date().getMonth()).length};}
function isPlanLimitExceeded(companyId,limitName){const p=getCompanyPlan(companyId),u=getPlanUsage(companyId);if(!p)return false;const map={maxActiveSurveys:'activeSurveys',maxResponsesMonth:'responsesMonth',maxManagers:'managers',maxEmployees:'employees',maxEmailsMonth:'emailsMonth'};const used=u[map[limitName]],limit=Number(p[limitName]);return Number.isFinite(limit)&&limit>=0&&used>=limit;}
function canUseFeature(company,featureId){const plan=typeof company==='string'?getCompanyPlan(company):planById(company?.planId);return !!plan&&(Array.isArray(plan.features)&&plan.features.includes(featureId)||Array.isArray(plan.enabledModules)&&plan.enabledModules.includes(featureId)||plan[featureId]===true);}
function canCreateSurvey(companyId){const c=companyById(companyId);if(!c||c.status!=='active')return false;if(isPlanLimitExceeded(companyId,'maxActiveSurveys'))return false;const p=getCompanyPlan(companyId);return !p||p.maxActiveSurveys<0||scopedSurveys(companyId).filter(s=>surveyIsActive(s)).length<p.maxActiveSurveys;}


function firebaseCallable(name){const fn=window.ValoraFirebaseServices?.functions;if(!fn)throw new Error('Cloud Functions indisponíveis. Confira Firebase Functions no index.html.');return fn.httpsCallable(name);}
async function callPublicFunction(name,payload){const callable=firebaseCallable(name);const result=await callable(payload);return result.data;}
function isFirebaseMode(){return APP_CONFIG.STORAGE_MODE==='firebase';}

async function renderTakeSurvey(sid,token){
  renderShell();
  let s,f,companyLabel,lgpdText=state.settings.lgpdText||LGPD_TEXT;
  if(isFirebaseMode()){
    $('#app').innerHTML='<section class="section"><div class="container"><div class="card"><h1>Validando link seguro…</h1><p>Aguarde enquanto confirmamos a pesquisa no backend.</p></div></div></section>';
    try{
      const payload=await callPublicFunction('validateSurveyLink',{surveyId:sid,token});
      publicSurveyCache.set(sid,payload);
      s=payload.survey;f=payload.form;companyLabel=payload.company?.name||'Valora Group';lgpdText=payload.lgpd?.text||lgpdText;
    }catch(err){return $('#app').innerHTML=invalidLink('Link inválido ou indisponível',err?.message||'Solicite um novo link ao gestor da pesquisa.');}
  }else{
    s=state.surveys.find(x=>x.id===sid);f=s?formById(s.formId):null;companyLabel=companyName(s?.companyId);
    if(!s||!f||s.token!==token)return $('#app').innerHTML=invalidLink('Link inválido','Solicite um novo link ao gestor da pesquisa.');
    if(!surveyIsActive(s))return $('#app').innerHTML=invalidLink('Pesquisa encerrada ou expirada',`Validade: ${brDate(s.expiresAt)}. Solicite a renovação ao gestor.`);
  }
  const user=currentUser()?.role==='participante'?currentUser():null;
  $('#app').innerHTML=`<section class="section"><div class="container survey-container"><div class="page-head"><div><div class="breadcrumb">Link seguro › Identificação › LGPD › Respostas › Resultado</div><h1 class="page-title">${esc(s.title)}</h1><p>${esc(companyLabel)}</p></div><span class="badge">${Number(f.timeMin||5)} minutos</span></div><div class="page-help"><b>Como funciona:</b> informe seus dados, leia o termo, responda as perguntas e envie. Campos marcados com * são obrigatórios. O cálculo segue o método definido no formulário.</div><div class="survey-steps"><span class="step active">1. Identificação</span><span class="step active">2. LGPD</span><span class="step active">3. Respostas</span><span class="step">4. Resultado</span></div><form class="grid" data-form="takeSurvey" novalidate><input type="hidden" name="surveyId" value="${s.id}"><input type="hidden" name="token" value="${esc(token)}"><div class="card"><h3>Identificação e acesso ao histórico</h3>${s.requireIdentification===false?'<p>Esta pesquisa permite participação sem identificação nominal. Um e-mail ainda é necessário caso você queira receber e consultar o resultado.</p>':''}<div class="form-grid"><div class="field"><label>Tipo de participante *</label><select name="personType"><option value="fisica">Pessoa física</option><option value="juridica">Empresa / CNPJ</option></select></div><div class="field"><label>Nome ou razão social *</label><input name="name" value="${esc(user?.name||'')}" required spellcheck="true"></div><div class="field"><label>E-mail *</label><input name="email" type="email" value="${esc(user?.email||'')}" required></div><div class="field"><label>Senha para consultar o histórico *</label><input name="accessPassword" type="password" minlength="6" value="${user?'123456':''}" required><span class="field-help">Use ao menos 6 caracteres. Para a demonstração, você poderá usar esta senha depois.</span></div><div class="field"><label>Telefone</label><input name="phone" value="${esc(user?.phone||'')}"></div><div class="field"><label>CPF/CNPJ</label><div class="inline-field"><input name="document"><button type="button" class="btn btn-soft btn-mini" data-action="lookupCnpj">Buscar CNPJ</button></div></div><div class="field"><label>CEP</label><div class="inline-field"><input name="cep"><button type="button" class="btn btn-soft btn-mini" data-action="lookupCep">Buscar CEP</button></div></div><div class="field"><label>Endereço</label><input name="address"></div></div><label class="checkline"><input name="isWhatsapp" type="checkbox"><span>O telefone informado também é WhatsApp</span></label><label class="checkline"><input name="sendEmail" type="checkbox" checked><span>Quero receber o resultado por e-mail</span></label></div>${s.lgpdRequired!==false?`<div class="card"><h3>Privacidade e LGPD</h3><details class="legal-box" open><summary>Leia o termo antes de continuar</summary><div>${nl2br(lgpdText)}</div></details><label class="checkline"><input name="lgpdConsent" type="checkbox" required><span>Li e aceito o tratamento dos dados para participação, cálculo, histórico e comunicação escolhida. *</span></label></div>`:''}<div class="card"><h3>${esc(f.name)}</h3><p>${esc(f.description)}</p>${f.questions.map((q,i)=>takeQuestion(q,i)).join('')}</div><button class="btn btn-primary btn-block">Enviar respostas e ver resultado</button></form></div></section>`;
}
function invalidLink(title,message){return `<section class="section"><div class="container"><div class="danger-box"><b>${esc(title)}</b><br>${esc(message)}</div><button class="btn btn-primary" data-action="goHome">Voltar à página inicial</button></div></section>`;}
function takeQuestion(q,i){
  const name=`q_${q.id}`,req=q.required?'<span class="required-mark">*</span>':'';let control='';
  if(q.type==='scale')control=`<div class="scale-row">${[1,2,3,4,5].map(n=>`<label><input type="radio" name="${name}" value="${n}"><span>${n}</span><small>${n===1?'Discordo totalmente':n===5?'Concordo totalmente':''}</small></label>`).join('')}</div>`;
  else if(q.type==='single'||q.type==='singleCorrect')control=`<div class="choice-list">${q.options.map(o=>`<label class="checkline"><input type="radio" name="${name}" value="${o.id}"><span>${esc(o.text)}</span></label>`).join('')}</div>`;
  else if(q.type==='multiple')control=`<div class="choice-list">${q.options.map(o=>`<label class="checkline"><input type="checkbox" name="${name}" value="${o.id}"><span>${esc(o.text)}</span></label>`).join('')}</div>`;
  else if(q.type==='shortText')control=`<input type="text" name="${name}" placeholder="Digite uma resposta curta" spellcheck="true">`;
  else control=`<textarea name="${name}" placeholder="Digite sua resposta" spellcheck="true"></textarea>`;
  return `<div class="survey-question" data-question-id="${q.id}" data-required="${q.required?'true':'false'}" data-type="${q.type}"><h3>${i+1}. ${esc(q.text)} ${req}</h3>${q.help?`<p class="field-help">${esc(q.help)}</p>`:''}${control}</div>`;
}
async function submitSurvey(form){
  const fd=data(form);
  if(isFirebaseMode()){
    const cached=publicSurveyCache.get(fd.surveyId);
    const f=cached?.form;if(!f)return toast('Valide o link novamente antes de enviar.','error');
    if(!fd.name||!fd.email||!fd.accessPassword)return toast('Preencha nome, e-mail e senha.','error');
    if(cached.survey?.lgpdRequired!==false&&!fd.lgpdConsent)return toast('O aceite LGPD é obrigatório.','error');
    const answers={};for(const q of f.questions){const key=`q_${q.id}`,value=fd[key];if(q.required&&(!value||(Array.isArray(value)&&!value.length)))return toast(`Responda a pergunta: ${q.text}`,'error');answers[q.id]=value??(q.type==='multiple'?[]:'');}
    const participant={personType:fd.personType,name:fd.name,email:fd.email,phone:fd.phone||'',isWhatsapp:!!fd.isWhatsapp,document:fd.document||'',cep:fd.cep||'',address:fd.address||'',sendEmail:!!fd.sendEmail};
    try{
      const res=await callPublicFunction('submitSurveyResponse',{surveyId:fd.surveyId,token:fd.token,participant,answers,lgpdConsent:!!fd.lgpdConsent,communicationConsent:!!fd.sendEmail});
      toast('Respostas enviadas com segurança.','success');
      const clean=location.href.split('?')[0].split('#')[0];
      history.replaceState({},'',`${clean}?result=${encodeURIComponent(res.responseId)}&rt=${encodeURIComponent(res.resultToken)}`);
      return renderResult(res.responseId,true,res.resultToken);
    }catch(err){return toast(err?.message||'Não foi possível enviar a resposta.','error');}
  }
  const s=state.surveys.find(x=>x.id===fd.surveyId),f=s?formById(s.formId):null;if(!s||!f||s.token!==fd.token)return toast('A pesquisa não está mais disponível.','error');if(!surveyIsActive(s))return toast('A pesquisa expirou ou foi encerrada.','error');if(!fd.name||!fd.email||!fd.accessPassword)return toast('Preencha nome, e-mail e senha.','error');if(s.lgpdRequired!==false&&!fd.lgpdConsent)return toast('O aceite LGPD é obrigatório.','error');
  const existingResponses=state.responses.filter(r=>r.surveyId===s.id&&r.participant.email.toLowerCase()===fd.email.toLowerCase());if(existingResponses.length&&!s.allowRepeat)return toast('Este e-mail já respondeu e a pesquisa não permite nova tentativa.','error');const company=companyById(s.companyId),plan=planById(company?.planId);if(plan?.maxResponsesMonth>=0&&responsesThisMonth(s.companyId)>=plan.maxResponsesMonth)return toast('O limite mensal de respostas do plano foi atingido.','error');
  const answers={};for(const q of f.questions){const key=`q_${q.id}`,value=fd[key];if(q.required&&(!value||(Array.isArray(value)&&!value.length)))return toast(`Responda a pergunta: ${q.text}`,'error');answers[q.id]=value??(q.type==='multiple'?[]:'');}
  const participant={personType:fd.personType,name:fd.name,email:fd.email,phone:fd.phone||'',isWhatsapp:!!fd.isWhatsapp,document:fd.document||'',cep:fd.cep||'',address:fd.address||'',lgpdConsent:!!fd.lgpdConsent,sendEmail:!!fd.sendEmail};const result=calculateResult(f,answers);const response={id:uid('resp'),surveyId:s.id,formId:f.id,companyId:s.companyId,participant,answers,createdAt:nowIso(),resultToken:secureToken(),...result,emailStatus:'pending'};state.responses.push(response);markInvitationAnswered(s,participant.email);
  let user=state.users.find(u=>u.email.toLowerCase()===participant.email.toLowerCase());if(!user){user={id:uid('u'),name:participant.name,email:participant.email,password:fd.accessPassword,role:'participante',companyId:s.companyId,phone:participant.phone,status:'active',createdAt:nowIso()};state.users.push(user);}else if(user.role==='participante'){user.name=participant.name;user.phone=participant.phone;user.password=fd.accessPassword;user.companyId=s.companyId;}
  state.session={userId:user.id,createdAt:nowIso()};audit('Resposta enviada','resposta',response.id,`${participant.email} — ${s.title}`);save();
  if(participant.sendEmail){const sent=await sendResultEmail(response,false);response.emailStatus=sent?'sent':'fallback';save();}
  renderResult(response.id,true);
}
function calculateSurveyResult(f,answers){
  // Função central de cálculo: usada por respostas, dashboards, relatórios e certificados. Textos qualitativos sem scoreWhenFilled não reduzem a nota. Múltipla escolha é limitada à pontuação máxima da pergunta.

  let rawScore=0,maxScore=0;const byDimension={},qualitative=[];const questionRatios=[];
  for(const q of f.questions){const a=answers[q.id];let raw=0,max=Number(q.maxScore||0);if(q.type==='scale'){const n=clamp(Number(a||0),0,5);max=max||5;raw=(n/5)*max;}else if(q.type==='single'){const o=q.options.find(x=>x.id===a);raw=Number(o?.score||0);max=max||Math.max(0,...q.options.map(x=>Number(x.score||0)));}else if(q.type==='multiple'){const arr=Array.isArray(a)?a:(a?[a]:[]);raw=q.options.filter(o=>arr.includes(o.id)).reduce((s,o)=>s+Number(o.score||0),0);max=max||q.options.filter(o=>Number(o.score)>0).reduce((s,o)=>s+Number(o.score||0),0);if(max>0)raw=Math.min(raw,max);}else if(q.type==='singleCorrect'){const o=q.options.find(x=>x.id===a);max=max||1;raw=o?.correct?max:Number(o?.score||0);}else{const text=String(a||'').trim();qualitative.push({question:q.text,answer:text});raw=text?Number(q.scoreWhenFilled||0):0;max=max||Number(q.scoreWhenFilled||0);}
    const weight=Math.max(0,Number(q.weight||1));const weightedRaw=raw*weight,weightedMax=max*weight;rawScore+=weightedRaw;maxScore+=weightedMax;const ratio=max>0?raw/max:0;questionRatios.push({ratio,weight});const dim=q.dimensionName||formDimensionName(f,q.dimensionId)||'Geral';if(!byDimension[dim])byDimension[dim]={rawScore:0,maxScore:0,count:0};byDimension[dim].rawScore+=weightedRaw;byDimension[dim].maxScore+=weightedMax;byDimension[dim].count++;
  }
  let normalized5=0;if(f.scoringMethod==='average')normalized5=avg(questionRatios.filter(x=>x.weight>0).map(x=>x.ratio))*5;else if(f.scoringMethod==='weightedAverage'){const weights=questionRatios.reduce((s,x)=>s+x.weight,0);normalized5=weights?questionRatios.reduce((s,x)=>s+x.ratio*x.weight,0)/weights*5:0;}else normalized5=maxScore?rawScore/maxScore*5:0;normalized5=clamp(normalized5,0,5);Object.values(byDimension).forEach(d=>{d.normalized5=d.maxScore?clamp(d.rawScore/d.maxScore*5,0,5):0;d.percentage=d.normalized5/5*100;});const level=(f.resultBands||defaultBands()).find(b=>normalized5>=Number(b.from)&&normalized5<=Number(b.to))||defaultBands().at(-1);return {rawScore,maxScore,normalized5,percentage:normalized5/5*100,scoringMethod:f.scoringMethod,byDimension,level:deepClone(level),qualitative};
}
const calculateResult=calculateSurveyResult;

async function renderResult(id,afterSubmit=false,publicToken=''){
  renderShell();let r,s,companyLabel;
  if(isFirebaseMode()&&publicToken){
    $('#app').innerHTML='<section class="section"><div class="container"><div class="card"><h1>Carregando resultado seguro…</h1></div></div></section>';
    try{r=await callPublicFunction('getPublicResult',{responseId:id,resultToken:publicToken});publicResultCache.set(id,r);companyLabel='Valora Group';}
    catch(err){return $('#app').innerHTML=invalidLink('Resultado não encontrado',err?.message||'O registro solicitado não está disponível.');}
  }else{
    r=state.responses.find(x=>x.id===id);if(!r)return $('#app').innerHTML=invalidLink('Resultado não encontrado','O registro solicitado não está disponível.');if(!canViewResponse(r,publicToken))return $('#app').innerHTML=invalidLink('Acesso negado','Entre com o perfil participante ou gestor autorizado.');s=state.surveys.find(x=>x.id===r.surveyId);companyLabel=companyName(r.companyId);
  }
  $('#app').innerHTML=`<section class="section"><div class="container"><div class="result-hero"><div><span class="badge dark">Resultado individual</span><h1>${esc(s?.title||'Resultado')}</h1><p>${esc(companyLabel)} • ${brDate(r.createdAt)}</p><h2>${esc(r.level?.label||'Resultado')}</h2><p>${esc(r.level?.description||'')}</p></div><div class="result-score"><div class="time-ring"><div class="time-ring-inner"><div><strong>${Number(r.normalized5).toFixed(2)}</strong><span>/5</span></div></div></div></div></div>${afterSubmit?`<div class="success-box result-notice"><b>Respostas enviadas com sucesso.</b> O resultado foi salvo em sua área${r.participant.sendEmail?' e o envio por e-mail foi processado':''}.</div>`:''}<div class="kpi-grid result-kpis">${kpi('Pontuação',Number(r.rawScore).toFixed(1),`Máximo ${Number(r.maxScore).toFixed(1)}`)}${kpi('Índice normalizado',Number(r.normalized5).toFixed(2)+'/5',`${Number(r.percentage).toFixed(0)}%`)}${kpi('Método',scoringLabel(r.scoringMethod),'Definido pelo formulário')}${kpi('Nível',r.level?.label||'—','Faixa configurada')}</div><div class="grid grid-2"><div class="card"><h3>Resultado por dimensão</h3>${barList(Object.entries(r.byDimension||{}).map(([label,v])=>({label,valueLabel:Number(v.normalized5).toFixed(2)+'/5',percent:v.percentage})))}</div><div class="card"><h3>Próximos passos</h3><p>${esc(r.level?.recommendation||recommendationFor(r.normalized5))}</p><p><b>Leitura:</b> ${esc(r.level?.description||'Use as dimensões com menor índice como prioridade.')}</p></div></div>${certificateHtml(r)}<div class="table-actions result-actions"><button class="btn btn-primary" data-action="reportResponsePdf" data-id="${r.id}">Relatório PDF</button><button class="btn btn-secondary" data-action="certificatePdf" data-id="${r.id}">Certificado PDF</button><button class="btn btn-soft" data-action="certificatePng" data-id="${r.id}">Certificado PNG</button><button class="btn btn-soft" data-action="emailResult" data-id="${r.id}">Enviar por e-mail</button><button class="btn btn-ghost" data-action="goMyArea">Ir para minha área</button></div></div></section>`;
}
function certificateHtml(r){return `<div class="certificate" id="certificate_${r.id}"><img src="${LOGO_FULL}" alt="Valora Group"><h2>Certificado de Participação</h2><p>Certificamos que <b>${esc(r.participant.name)}</b> concluiu a pesquisa <b>${esc(surveyTitle(r.surveyId))}</b>.</p><p><b>Resultado:</b> ${Number(r.normalized5).toFixed(2)} / 5 — ${esc(r.level?.label||'')}</p><p>${esc(companyName(r.companyId))} • ${brDay(r.createdAt)}</p><p class="muted">Diagnóstico autoaplicado. Este documento não substitui certificação formal.</p></div>`;}
function recommendationFor(score){if(score<=2.2)return 'Estabilize a operação: defina um indicador crítico, alinhe a liderança e documente um processo essencial.';if(score<=3.4)return 'Fortaleça governança, feedbacks e desenvolvimento de talentos para ganhar consistência.';if(score<=4.4)return 'Aprimore inovação, benchmark e formação de lideranças para diferenciar a organização.';return 'Monitore anualmente, compartilhe boas práticas e avalie certificações formais compatíveis.';}
function canViewResponse(r,publicToken=''){if(publicToken&&r.resultToken&&publicToken===r.resultToken)return true;const u=currentUser();if(!u)return false;if(u.role==='admin_valora'||u.role==='consultor_valora')return true;if(['empresa_admin','gestor_pesquisa'].includes(u.role))return u.companyId===r.companyId;if(u.role==='participante')return u.email.toLowerCase()===r.participant.email.toLowerCase();return false;}
function filterUsersTable(){const q=String($('#employeeSearch')?.value||'').toLowerCase(),st=$('#employeeStatus')?.value||'',role=$('#employeeRole')?.value||'',dep=$('#employeeDepartment')?.value||'',em=$('#employeeEmail')?.value||'',portal=$('#employeePortal')?.value||'';$$('[data-user-row]').forEach(r=>{const show=(!q||r.dataset.name.includes(q))&&(!st||r.dataset.status===st)&&(!role||r.dataset.role===role)&&(!dep||r.dataset.department===dep)&&(!em||r.dataset.email===em)&&(!portal||r.dataset.portal===portal);r.style.display=show?'':'none';});updateEmployeeCount();}
function selectedEmployeeIds(){return $$('[data-employee-check]:checked').map(x=>x.value);}
function setEmployeeSelection(on){$$('[data-employee-check]').forEach(x=>{if(!x.disabled&&x.closest('tr')?.style.display!=='none')x.checked=!!on;});updateEmployeeCount();}
document.addEventListener('change',e=>{if(e.target.matches('[data-employee-check]'))updateEmployeeCount();});
function updateEmployeeCount(){const el=$('#employeeSelectedCount');if(el)el.textContent=`${selectedEmployeeIds().length} selecionado(s)`;}
function toggleUserStatus(id){const actor=currentUser(),u=state.users.find(x=>x.id===id);if(!u||!['admin_valora','empresa_admin'].includes(actor?.role))return;if(actor.role==='empresa_admin'&&u.companyId!==actor.companyId)return toast('Usuário fora do seu ambiente.','error');u.status=u.status==='inactive'?'active':'inactive';u.updatedAt=nowIso();audit(u.status==='active'?'Usuário reativado':'Usuário desativado','usuário',id,u.email);persist('Status atualizado.');rerenderPortal();}
function canDeleteResponse(){return ['admin_valora','empresa_admin'].includes(currentUser()?.role);}
function deleteResponse(id){const r=state.responses.find(x=>x.id===id);if(!r||!canDeleteResponse())return;confirmAction('Excluir resposta?',`Excluir o resultado de ${r.participant.name}?`,()=>{state.responses=state.responses.filter(x=>x.id!==id);audit('Resposta excluída','resposta',id,r.participant.email);persist('Resposta excluída.');rerenderPortal();});}

function reportResponsePdf(id){
  const r=state.responses.find(x=>x.id===id);if(!r)return;const s=state.surveys.find(x=>x.id===r.surveyId);const rows=Object.entries(r.byDimension||{}).map(([dimension,v])=>({dimension,score:Number(v.rawScore).toFixed(1),maximum:Number(v.maxScore).toFixed(1),index:Number(v.normalized5).toFixed(2),interpretation:dimensionRecommendation(v.normalized5)}));window.ValoraPDF.createReport({title:`Relatório individual — ${s?.title||'Valora Pulse™'}`,subtitle:`${r.participant.name} • ${companyName(r.companyId)} • ${brDate(r.createdAt)}`,metrics:[{label:'Índice',value:`${Number(r.normalized5).toFixed(2)} / 5`},{label:'Percentual',value:`${Number(r.percentage).toFixed(0)}%`},{label:'Nível',value:r.level?.label||'—'},{label:'Pontuação',value:`${Number(r.rawScore).toFixed(1)} / ${Number(r.maxScore).toFixed(1)}`}],columns:[{key:'dimension',label:'Dimensão',width:2.1},{key:'score',label:'Pontos',width:.8},{key:'maximum',label:'Máximo',width:.8},{key:'index',label:'Índice',width:.7},{key:'interpretation',label:'Leitura',width:2.4}],rows},`relatorio-${slug(r.participant.name)}-${slug(s?.title)}.pdf`);audit('Relatório PDF exportado','resposta',id,r.participant.email);}
function dimensionRecommendation(n){if(n<=2.2)return 'Fragilidade crítica';if(n<=3.4)return 'Oportunidade de evolução';if(n<=4.4)return 'Consistência';return 'Excelência';}
function certificatePdf(id){const r=state.responses.find(x=>x.id===id);if(!r)return;window.ValoraPDF.createCertificate({name:r.participant.name,survey:surveyTitle(r.surveyId),score:`${Number(r.normalized5).toFixed(2)} / 5`,level:r.level?.label||'',company:companyName(r.companyId),date:brDay(r.createdAt)},`certificado-${slug(r.participant.name)}.pdf`);audit('Certificado PDF exportado','resposta',id,r.participant.email);}
function certificatePng(id){
  const r=state.responses.find(x=>x.id===id);if(!r)return;const canvas=document.createElement('canvas');canvas.width=1500;canvas.height=1000;const c=canvas.getContext('2d');c.fillStyle='#ffffff';c.fillRect(0,0,1500,1000);c.strokeStyle='#0b3d4d';c.lineWidth=28;c.strokeRect(34,34,1432,932);c.fillStyle='#0b3d4d';c.fillRect(70,70,1360,170);c.textAlign='center';c.fillStyle='#ffffff';c.font='700 56px Arial';c.fillText('VALORA GROUP',750,150);c.font='28px Arial';c.fillText('GOVERNANÇA • CONTROLLER • ADVISORY',750,202);c.fillStyle='#082a37';c.font='700 54px Arial';c.fillText('CERTIFICADO DE PARTICIPAÇÃO',750,345);c.font='30px Arial';c.fillText('Certificamos que',750,405);c.font='700 46px Arial';wrapCanvas(c,r.participant.name,750,475,1200,54);c.font='27px Arial';wrapCanvas(c,`concluiu a pesquisa “${surveyTitle(r.surveyId)}”`,750,585,1230,38);c.fillStyle='#0b3d4d';c.font='700 42px Arial';c.fillText(`${Number(r.normalized5).toFixed(2)} / 5 — ${r.level?.label||''}`,750,720);c.fillStyle='#365d6d';c.font='25px Arial';c.fillText(`${companyName(r.companyId)} • ${brDay(r.createdAt)}`,750,800);c.font='20px Arial';c.fillText('Diagnóstico autoaplicado. Não substitui certificação formal.',750,860);const a=document.createElement('a');a.href=canvas.toDataURL('image/png');a.download=`certificado-${slug(r.participant.name)}.png`;a.click();audit('Certificado PNG exportado','resposta',id,r.participant.email);
}
function wrapCanvas(ctx,text,x,y,maxWidth,lineHeight){const words=String(text).split(' ');let line='';for(const word of words){const test=line?`${line} ${word}`:word;if(ctx.measureText(test).width>maxWidth&&line){ctx.fillText(line,x,y);line=word;y+=lineHeight;}else line=test;}if(line)ctx.fillText(line,x,y);}

function reportRows(scope){
  let rows;if(String(scope).startsWith('response:'))rows=window.ValoraAnalytics.completedResponses(state).filter(r=>r.id===String(scope).split(':')[1]);else if(scope==='admin')rows=window.ValoraAnalytics.completedResponses(state);else if(scope==='company'||scope==='empresa')rows=window.ValoraAnalytics.completedResponses(state,{companyId:currentCompany()?.id});else if(scope==='participant'||scope==='participante')rows=window.ValoraAnalytics.completedResponses({responses:responsesForUser(currentUser())});else rows=window.ValoraAnalytics.completedResponses(state);
  return rows.map(r=>({participant:r.participant.name,email:r.participant.email,company:companyName(r.companyId),survey:surveyTitle(r.surveyId),date:brDate(r.createdAt),raw:`${Number(r.rawScore).toFixed(1)}/${Number(r.maxScore).toFixed(1)}`,index:Number(r.normalized5).toFixed(2),level:r.level?.label||'',method:scoringLabel(r.scoringMethod)}));
}
function exportReport(scope,format){
  const report=window.ValoraReports?buildReportForScope(scope):null;
  if(!report){const rows=reportRows(scope);return downloadText(`relatorio-${scope}.json`,JSON.stringify(rows,null,2),'application/json');}
  const rows=flattenReportRows(report), filename=`${slug(report.title)}-${new Date().toISOString().slice(0,10)}`;
  const metrics=Object.entries(report.metrics||{}).slice(0,4).map(([label,value])=>({label,value:typeof value==='object'?'—':String(value)}));
  const columns=[{key:'section',label:'Seção',width:1},{key:'item',label:'Item',width:1.4},{key:'value',label:'Valor/ação',width:2.6},{key:'percent',label:'%',width:.7},{key:'priority',label:'Prioridade',width:.8},{key:'owner',label:'Responsável',width:1}];
  if(format==='pdf')window.ValoraPDF.createReport({title:report.title,subtitle:`${report.subtitle||''} • ${report.summary||''}`,metrics,columns,rows},`${filename}.pdf`);
  else if(format==='json')downloadText(`${filename}.json`,JSON.stringify(report,null,2),'application/json');
  else if(format==='csv')downloadText(`${filename}.csv`,toCsv(rows),'text/csv;charset=utf-8');
  else if(format==='excel')downloadText(`${filename}.xls`,excelReportHtml(report,rows),'application/vnd.ms-excel;charset=utf-8');
  else if(format==='word')downloadText(`${filename}.doc`,wordReportHtml(report,rows),'application/msword;charset=utf-8');
  audit(`Relatório ${String(format).toUpperCase()} gerado`,'relatório',report.type,JSON.stringify({scope,type:report.type,filters:reportFiltersFromUi()}));
}
function toCsv(rows){if(!rows.length)return '';const keys=Object.keys(rows[0]);const q=v=>`"${String(v??'').replace(/"/g,'""')}"`;return '\uFEFF'+[keys.map(q).join(';'),...rows.map(r=>keys.map(k=>q(r[k])).join(';'))].join('\n');}
function excelHtml(title,rows){const keys=rows.length?Object.keys(rows[0]):[];return `\uFEFF<html><head><meta charset="utf-8"></head><body><h1>${esc(title)}</h1><table border="1"><thead><tr>${keys.map(k=>`<th>${esc(k)}</th>`).join('')}</tr></thead><tbody>${rows.map(r=>`<tr>${keys.map(k=>`<td>${esc(r[k])}</td>`).join('')}</tr>`).join('')}</tbody></table></body></html>`;}
function excelReportHtml(report,rows){return `\uFEFF<html><head><meta charset="utf-8"><style>body{font-family:Arial;color:#082a37}h1{color:#0b3d4d}.card{border:1px solid #aacbd3;padding:12px;margin:8px 0}table{border-collapse:collapse;width:100%}th,td{border:1px solid #aacbd3;padding:7px;text-align:left}th{background:#eaf6f8}</style></head><body><h1>${esc(report.title)}</h1><p>${esc(report.subtitle||'')}</p><div class="card"><b>Sumário executivo</b><p>${esc(report.summary||'')}</p></div><h2>Resumo</h2>${excelHtml('',Object.entries(report.metrics||{}).map(([item,value])=>({item,value:typeof value==='object'?JSON.stringify(value):value})))}<h2>Dados</h2>${excelHtml('',rows)}</body></html>`;}
function wordReportHtml(report,rows){return excelReportHtml(report,rows).replace('<h2>Dados</h2>','<h2>Recomendações</h2><ul>'+(report.recommendations||[]).map(x=>`<li>${esc(x)}</li>`).join('')+'</ul><h2>Plano de ação</h2>');}
function wordHtml(title,rows){return `\uFEFF<html><head><meta charset="utf-8"><style>body{font-family:Arial;color:#082a37}h1{color:#0b3d4d}table{border-collapse:collapse;width:100%}th,td{border:1px solid #aacbd3;padding:7px;text-align:left}th{background:#eaf6f8}</style></head><body><h1>${esc(title)}</h1><p>Valora Pulse™ • ${new Date().toLocaleString('pt-BR')}</p>${excelHtml('',rows).replace(/^.*<body>|<\/body>.*$/gs,'')}</body></html>`;}
function downloadText(name,text,type){const blob=new Blob([text],{type});const url=URL.createObjectURL(blob);const a=document.createElement('a');a.href=url;a.download=name;a.click();setTimeout(()=>URL.revokeObjectURL(url),1500);}

function brandedEmailPreview(kicker,title,link){return `<div class="email-brand"><img src="${LOGO_FULL}" alt="Valora Group"><span>${esc(kicker)}</span><h3>${esc(title)}</h3><p>Mensagem com identidade visual Valora Group, chamada para ação e link seguro.</p>${link?`<span class="email-button">Acessar pesquisa</span>`:''}</div>`;}
function emailHtml(title,message,buttonLabel='',buttonUrl=''){return `<!doctype html><html><body style="margin:0;background:#eef7f9;font-family:Arial,sans-serif;color:#082a37"><div style="max-width:680px;margin:24px auto;background:#fff;border:1px solid #c8dde4;border-radius:22px;overflow:hidden"><div style="background:#0b3d4d;padding:30px;text-align:center"><img src="cid:valora-logo" alt="Valora Group" style="max-width:240px;border-radius:12px"></div><div style="padding:32px"><h1 style="font-size:27px;color:#082a37">${esc(title)}</h1><div style="font-size:17px;line-height:1.65;color:#365d6d">${nl2br(message)}</div>${buttonUrl?`<p style="margin:28px 0"><a href="${esc(buttonUrl)}" style="background:#0b3d4d;color:#fff;text-decoration:none;padding:14px 22px;border-radius:999px;font-weight:bold">${esc(buttonLabel||'Acessar')}</a></p>`:''}<p style="font-size:13px;color:#557785">Valora Group • Governança • Controller • Advisory</p></div></div></body></html>`;}
async function sendEmail(payload){
  try{
    if(isFirebaseMode()){
      const res=await firebaseCallable('sendEmail')({...payload,templateType:payload.templateType||'operational',payload:{text:payload.text||'',message:payload.text||'',buttonUrl:payload.buttonUrl||payload.link||''}});
      if(!res.data?.sent)throw new Error('Envio não confirmado.');
      toast('E-mail enviado com segurança pelo Firebase.','success');return true;
    }
    const res=await fetch('/api/email/send',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(payload)});const body=await res.json().catch(()=>({}));if(!res.ok)throw new Error(body.error||`Erro HTTP ${res.status}`);toast(body.mode==='outbox'?'E-mail criado na caixa de saída de teste.':'E-mail enviado.','success');return true;
  }catch(err){console.warn('Serviço de e-mail indisponível',err);const mailto=`mailto:${encodeURIComponent(payload.to)}?subject=${encodeURIComponent(payload.subject)}&body=${encodeURIComponent(payload.text||'')}`;toast(isFirebaseMode()?`Não foi possível enviar pelo Firebase: ${err.message}`:'O serviço local de e-mail não respondeu. Abrimos o cliente de e-mail como alternativa.','warn');if(!isFirebaseMode())location.href=mailto;return false;}
}
async function sendInviteEmail(form){const fd=data(form),s=state.surveys.find(x=>x.id===fd.surveyId);if(!s)return;const link=buildSurveyLink(s);const ok=await sendEmail({to:fd.email,toName:fd.name,subject:fd.subject,text:fd.message,html:emailHtml('Convite para pesquisa',fd.message,'Responder pesquisa',link),templateType:'invite',surveyId:s.id,buttonUrl:link});recordInvitation(s,fd.email,fd.name,link,ok?'sent':'failed');audit(ok?'Convite enviado':'Convite acionado por fallback','pesquisa',s.id,fd.email);if(ok)closeModal();}
function markInvitationAnswered(s,email){const inv=state.invitations.find(i=>i.surveyId===s.id&&i.email.toLowerCase()===String(email).toLowerCase());if(inv){inv.status='answered';inv.answeredAt=nowIso();inv.updatedAt=nowIso();}}
function recordInvitation(s,email,name,link,status='pending'){const existing=state.invitations.find(i=>i.surveyId===s.id&&i.email.toLowerCase()===String(email).toLowerCase());const payload={surveyId:s.id,companyId:s.companyId,email,name,link,status,updatedAt:nowIso(),sentAt:status==='sent'?nowIso():''};if(existing)Object.assign(existing,payload);else state.invitations.push({id:uid('invte'),createdAt:nowIso(),...payload});save();}
function openBulkInvite(surveyId='',userIds=[]){const s=surveyId?state.surveys.find(x=>x.id===surveyId):null;const companyId=s?.companyId||currentCompany()?.id;const surveys=scopedSurveys(companyId).filter(s=>surveyIsActive(s));const employees=state.users.filter(u=>u.companyId===companyId&&u.status!=='inactive'&&u.email&&u.receivesEmail!==false);const selected=new Set(userIds);const byRole=Object.fromEntries(COMPANY_ROLES.map(r=>[r,employees.filter(u=>u.role===r).length]));const byDept={};employees.forEach(u=>{byDept[u.department||'Sem área']=(byDept[u.department||'Sem área']||0)+1;});openModal('Enviar questionários por e-mail',`<form class="grid" data-form="bulkInvite"><div class="page-help"><b>Fluxo seguro:</b> escolha a pesquisa ativa e filtre por perfil/departamento. Inativos, sem e-mail, com recebe e-mail = não e convidados sem e-mail válido são bloqueados.</div><div class="kpi-grid">${kpi('Funcionários',state.users.filter(u=>u.companyId===companyId).length,'total')}${kpi('Ativos com e-mail',employees.length,'elegíveis')}${kpi('Selecionados',selected.size||employees.length,'pré-seleção')}</div><div class="field"><label>Pesquisa ativa</label><select name="surveyId">${surveys.map(x=>`<option value="${x.id}" ${s?.id===x.id?'selected':''}>${esc(x.title)}</option>`).join('')}</select></div><div class="card"><b>Por perfil:</b> ${Object.entries(byRole).filter(([,v])=>v).map(([r,v])=>`${esc(ROLE_LABELS[r])}: ${v}`).join(' • ')||'—'}<br><b>Por departamento:</b> ${Object.entries(byDept).map(([d,v])=>`${esc(d)}: ${v}`).join(' • ')||'—'}</div><div class="card table-wrap"><table class="table"><thead><tr><th>Enviar</th><th>Funcionário</th><th>Perfil</th><th>Departamento</th></tr></thead><tbody>${employees.map(u=>`<tr><td><input type="checkbox" name="userIds" value="${u.id}" ${selected.has(u.id)||(!selected.size&&surveyId)?'checked':''}></td><td><b>${esc(u.name)}</b><br><span class="muted">${esc(u.email)}</span></td><td>${esc(ROLE_LABELS[u.role]||u.role)}</td><td>${esc(u.department||'—')}</td></tr>`).join('')||'<tr><td colspan="4">Cadastre funcionários ativos antes de enviar.</td></tr>'}</tbody></table></div><div class="confirm-actions"><button type="button" class="btn btn-soft" data-action="closeModal">Cancelar</button><button class="btn btn-primary">Enviar por e-mail</button></div></form>`,'large');}

async function sendBulkInvite(form){const fd=data(form),s=state.surveys.find(x=>x.id===fd.surveyId);const ids=Array.isArray(fd.userIds)?fd.userIds:(fd.userIds?[fd.userIds]:[]);if(!s||!canManageCompany(s.companyId)||!can(currentUser(),'canSendInvites')||!moduleEnabled('convitesEmail'))return toast(PERMISSION_DENIED_MESSAGE,'error');if(isPlanLimitExceeded(s.companyId,'maxEmailsMonth'))return toast('Limite mensal de e-mails do plano atingido.','error');if(!ids.length)return toast('Selecione ao menos um funcionário.','error');const recipients=ids.map(id=>state.users.find(x=>x.id===id&&x.companyId===s.companyId)).filter(Boolean);if(isFirebaseMode()){const link=buildSurveyLink(s);const vars={pesquisa:s.title,empresa:companyName(s.companyId),link,validade:brDay(s.expiresAt)};const subject=fillTemplate(state.settings.inviteSubject,vars)||`Convite: ${s.title}`;const message=fillTemplate(state.settings.inviteBody,vars)+`\n\nAviso LGPD: seus dados serão usados para identificação, cálculo do resultado e auditoria da pesquisa.`;try{const res=(await firebaseCallable('sendSurveyInvitations')({payload:{surveyId:s.id,subject,message,recipients:recipients.map(u=>({id:u.id,participantId:u.uid||u.id,email:u.email,name:u.name,role:u.role,department:u.department||u.area||'',status:u.status,receivesEmail:u.receivesEmail!==false,link}))}})).data;toast(`${res.sent}/${res.processed} convite(s) enviados pelo Firebase.`,res.sent?'success':'warn');if(repository.loadStoreFromFirestore)await repository.loadStoreFromFirestore();closeModal();rerenderPortal();return;}catch(err){toast(`Falha no envio Firebase: ${err.message}`,'error');return;}}let okCount=0;for(const u of recipients){if(!u||u.status==='inactive'||!u.email||u.receivesEmail===false)continue;const link=buildSurveyLink(s);const vars={pesquisa:s.title,empresa:companyName(s.companyId),link,validade:brDay(s.expiresAt),nome:u.name};const subject=fillTemplate(state.settings.inviteSubject,vars);const message=fillTemplate(state.settings.inviteBody,vars)+`\n\nAviso LGPD: seus dados serão usados para identificação, cálculo do resultado e auditoria da pesquisa.`;const ok=await sendEmail({to:u.email,toName:u.name,subject,text:message,html:emailHtml('Convite para pesquisa',message,'Responder pesquisa',link),templateType:'invite',surveyId:s.id,buttonUrl:link});recordInvitation(s,u.email,u.name,link,ok?'sent':'failed');if(ok)okCount++;}audit('Convites em lote processados','pesquisa',s.id,`${okCount}/${ids.length} enviados`);toast(`${okCount}/${ids.length} convite(s) enviados ou colocados no outbox.`,okCount?'success':'warn');closeModal();rerenderPortal();}
function openResultEmail(id){const r=state.responses.find(x=>x.id===id);if(!r)return;const s=state.surveys.find(x=>x.id===r.surveyId),link=buildResultLink(r);const subject=fillTemplate(state.settings.resultSubject,{nome:r.participant.name,empresa:companyName(r.companyId),pesquisa:s?.title||'',resultado:Number(r.normalized5).toFixed(2),nivel:r.level?.label||'',link});const message=fillTemplate(state.settings.resultBody,{nome:r.participant.name,empresa:companyName(r.companyId),pesquisa:s?.title||'',resultado:Number(r.normalized5).toFixed(2),nivel:r.level?.label||'',link});openModal('Enviar resultado por e-mail',`<form class="grid" data-form="resultEmail"><input type="hidden" name="responseId" value="${r.id}"><div class="field"><label>Destinatário</label><input name="email" type="email" value="${esc(r.participant.email)}" required></div><div class="field"><label>Assunto</label><input name="subject" value="${esc(subject)}"></div><div class="field"><label>Mensagem</label><textarea name="message">${esc(message)}</textarea></div>${brandedEmailPreview('Resultado individual',s?.title||'Valora Pulse™',link)}<div class="confirm-actions"><button type="button" class="btn btn-soft" data-action="closeModal">Cancelar</button><button class="btn btn-primary">Enviar resultado</button></div></form>`,'large');}
async function sendResultEmail(responseOrId,showToast=true,override=null){const r=typeof responseOrId==='string'?state.responses.find(x=>x.id===responseOrId):responseOrId;if(!r)return false;const s=state.surveys.find(x=>x.id===r.surveyId),link=buildResultLink(r);const vars={nome:r.participant.name,empresa:companyName(r.companyId),pesquisa:s?.title||'',resultado:Number(r.normalized5).toFixed(2),nivel:r.level?.label||'',link};const subject=override?.subject||fillTemplate(state.settings.resultSubject,vars);const message=override?.message||fillTemplate(state.settings.resultBody,vars);const to=override?.email||r.participant.email;const ok=await sendEmail({to,toName:r.participant.name,subject,text:message,html:emailHtml('Seu resultado Valora Pulse™',message,'Ver resultado',link),templateType:'result',surveyId:r.surveyId,responseId:r.id,buttonUrl:link});audit(ok?'Resultado enviado por e-mail':'Resultado acionado por fallback','resposta',r.id,to);if(showToast&&ok)toast('Resultado enviado.','success');return ok;}
async function submitResultEmail(form){const fd=data(form);const ok=await sendResultEmail(fd.responseId,true,{email:fd.email,subject:fd.subject,message:fd.message});if(ok)closeModal();}
function buildResultLink(r){const base=location.href.split('?')[0].split('#')[0];const u=new URL(base);u.searchParams.set('result',r.id);u.searchParams.set('rt',r.resultToken||'');return u.toString();}

async function saveSettings(form){
  const fd=data(form);state.settings.featuredSurveyId=fd.featuredSurveyId||'';state.settings.contactEmail=fd.contactEmail||'';state.settings.whatsappEnabled=!!fd.whatsappEnabled;state.settings.whatsappNumber=fd.whatsappNumber||'';state.settings.inviteSubject=fd.inviteSubject||'';state.settings.inviteBody=fd.inviteBody||'';state.settings.resultSubject=fd.resultSubject||'';state.settings.resultBody=fd.resultBody||'';state.settings.lgpdText=fd.lgpdText||LGPD_TEXT;state.settings.faq=parseFaq(fd.faqText);state.settings.email={mode:fd.emailMode||'outbox',senderName:fd.senderName||'Valora Group',senderEmail:fd.senderEmail||DEFAULT_SENDER,smtpUsername:fd.smtpUsername||DEFAULT_SENDER,smtpHost:fd.smtpHost||'',smtpPort:Number(fd.smtpPort||587),smtpSecurity:fd.smtpSecurity||'starttls'};
  let serverOk=false;if(isFirebaseMode()){toast('Configurações salvas. Em produção, SMTP é configurado via Secret Manager/variáveis de ambiente.','warn');}else try{const res=await fetch('/api/email/config',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({...state.settings.email,password:fd.smtpPassword||''})});serverOk=res.ok;if(!res.ok){const b=await res.json().catch(()=>({}));throw new Error(b.error||'Não foi possível configurar o servidor de e-mail.');}}catch(err){toast(`Configurações locais salvas. Serviço de e-mail: ${err.message}`,'warn');}
  audit('Configurações globais salvas','configuração','global',`Home, e-mail, WhatsApp, FAQ e LGPD${serverOk?' + servidor':''}`);save();toast('Configurações salvas.','success');renderShell();rerenderPortal();
}
async function sendTestEmail(){const form=$('form[data-form="settings"]');if(!form)return;const fd=data(form);if(!isFirebaseMode())await saveEmailServerConfig(fd);const to=fd.testRecipient||fd.contactEmail;if(!to)return toast('Informe um destinatário para o teste.','error');await sendEmail({to,toName:'Teste Valora',subject:'Teste de e-mail — Valora Pulse™',text:'Este é um teste do remetente configurado na administração do Valora Pulse™.',html:emailHtml('E-mail de teste','A configuração de envio do Valora Pulse™ está funcionando. Este teste usa a identidade visual da Valora Group.','Abrir Valora Pulse',location.href.split('#')[0]),templateType:'test',buttonUrl:location.href.split('#')[0]});audit('E-mail de teste solicitado','e-mail','test',to);updateEmailStatus();}
async function saveEmailServerConfig(fd){if(isFirebaseMode())throw new Error('Em produção Firebase, configure SMTP via Secret Manager/variáveis de ambiente, não pelo navegador.');const cfg={mode:fd.emailMode||'outbox',senderName:fd.senderName||'Valora Group',senderEmail:fd.senderEmail||DEFAULT_SENDER,smtpUsername:fd.smtpUsername||DEFAULT_SENDER,smtpHost:fd.smtpHost||'',smtpPort:Number(fd.smtpPort||587),smtpSecurity:fd.smtpSecurity||'starttls',password:fd.smtpPassword||''};const res=await fetch('/api/email/config',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(cfg)});const body=await res.json().catch(()=>({}));if(!res.ok)throw new Error(body.error||'Falha na configuração de e-mail.');return body;}
async function updateEmailStatus(){const el=$('#emailStatus');try{let b;if(isFirebaseMode()){b=(await firebaseCallable('getEmailStatus')({})).data;if(el)el.textContent=`Firebase Functions: ${b.configured?'configurado':'não configurado'} • remetente ${b.senderEmail||DEFAULT_SENDER}`;return;}const res=await fetch('/api/email/status');b=await res.json();if(el)el.textContent=`Serviço: ${b.mode==='smtp'?'SMTP':'caixa de saída'} • remetente ${b.senderEmail||DEFAULT_SENDER}`;}catch(_){if(el)el.textContent=isFirebaseMode()?'Cloud Function de e-mail indisponível.':'Serviço local indisponível; será usado o cliente de e-mail.';}}
