function openOnboardingWizard(){
  const c=currentCompany(), u=currentUser();if(!c)return;if(!['empresa_admin','gestor_pesquisa'].includes(u.role))return toast('Seu perfil permite visualizar resultados, mas não criar pesquisas.','warn');const m=onboardingMetrics(c.id);const forms=scopedForms(c.id);const surveys=m.activeSurveys;const employees=m.employees.filter(e=>e.status!=='inactive'&&e.email&&e.receivesEmail!==false);
  openModal('Configurar minha primeira pesquisa',`<form class="grid onboarding-wizard" data-form="onboardingWizard"><div class="wizard-steps"><span>1 Dados</span><span>2 Funcionários</span><span>3 Questionário</span><span>4 Pesquisa</span><span>5 Envio</span><span>6 Conclusão</span></div><div class="card"><h3>1 — Dados da empresa</h3><div class="form-grid"><div class="field"><label>Nome</label><input name="companyName" value="${esc(c.name||'')}"></div><div class="field"><label>E-mail</label><input name="companyEmail" type="email" value="${esc(c.email||'')}"></div><div class="field"><label>Telefone</label><input name="companyPhone" value="${esc(c.phone||'')}"></div><div class="field"><label>Responsável</label><input name="responsible" value="${esc(u.name||'')}"></div><div class="field span-2"><label>Endereço</label><input name="companyAddress" value="${esc(c.address||'')}"></div><div class="field"><label>Área principal</label><input name="mainArea" value="${esc(c.mainArea||'')}"></div></div></div><div class="card"><h3>2 — Funcionários</h3><p>Adicione pelo menos um respondente. Para vários, use uma linha por pessoa: Nome; e-mail; departamento; perfil.</p><textarea name="employees" placeholder="Ana Souza; ana@empresa.com; RH; participante">${employees.length?'': ''}</textarea></div><div class="card"><h3>3 — Questionário</h3><select name="formId"><option value="">Criar Diagnóstico Essencial de Maturidade</option>${forms.map(f=>`<option value="${f.id}">${esc(f.name)}</option>`).join('')}</select></div><div class="card"><h3>4 — Pesquisa</h3><div class="form-grid"><div class="field span-2"><label>Título</label><input name="surveyTitle" value="Diagnóstico Essencial de Maturidade" required></div><div class="field span-2"><label>Descrição</label><textarea name="surveyDescription">Pesquisa inicial guiada pelo onboarding Valora.</textarea></div><div class="field"><label>Início</label><input name="startsAt" type="date" value="${dateInput(nowIso())}"></div><div class="field"><label>Expiração</label><input name="expiresAt" type="date" value="${dateInput(datePlus(30))}"></div></div><label class="checkline"><input name="lgpdRequired" type="checkbox" checked><span>LGPD obrigatória</span></label><label class="checkline"><input name="showResult" type="checkbox" checked><span>Mostrar resultado ao participante</span></label><label class="checkline"><input name="allowRepeat" type="checkbox"><span>Permitir repetição</span></label></div><div class="card"><h3>5 — Envio</h3><p>Total elegível atual: <b>${employees.length}</b>. E-mails válidos serão selecionados automaticamente após salvar novos funcionários.</p>${planWarnings(c.id)}</div><div class="confirm-actions"><button type="button" class="btn btn-soft" data-action="closeModal">Cancelar</button><button class="btn btn-primary">Criar pesquisa e enviar convites</button></div></form>`,'large');
}
function essentialForm(companyId){return {id:uid('form'),companyId,global:false,name:'Diagnóstico Essencial de Maturidade',category:'Onboarding',description:'Modelo básico para iniciar o diagnóstico organizacional.',timeMin:5,status:'active',scoringMethod:'weightedAverage',dimensions:[{id:'dim_cultura',name:'Cultura',description:'Clareza e alinhamento cultural'},{id:'dim_processos',name:'Processos',description:'Padronização e execução'},{id:'dim_lideranca',name:'Liderança',description:'Gestão e comunicação'}],questions:[],resultBands:defaultBands(),createdAt:nowIso(),updatedAt:nowIso()};}
function saveOnboardingWizard(form){const c=currentCompany(),fd=data(form),actor=currentUser();if(!c)return;Object.assign(c,{name:fd.companyName,email:fd.companyEmail,phone:fd.companyPhone,address:fd.companyAddress,responsible:fd.responsible,mainArea:fd.mainArea,updatedAt:nowIso()});String(fd.employees||'').split('\n').map(x=>x.trim()).filter(Boolean).forEach(line=>{const [name,email,department,role]=line.split(';').map(x=>x?.trim());if(name&&email&&!state.users.some(u=>u.email.toLowerCase()===email.toLowerCase()))state.users.push({id:uid('u'),name,email,department:department||'',position:'Respondente',role:COMPANY_ROLES.includes(role)?role:'participante',companyId:c.id,status:'active',receivesEmail:true,portalAccess:true,type:'funcionario',password:'Empresa@2026',createdAt:nowIso(),createdBy:actor.id});});let formId=fd.formId;if(!formId){const f=essentialForm(c.id);f.questions=[blankQuestion('scale',f.dimensions[0]),blankQuestion('scale',f.dimensions[1]),blankQuestion('scale',f.dimensions[2])];f.questions[0].text='As pessoas conhecem os valores e objetivos da organização.';f.questions[1].text='Os processos principais são claros e seguidos pelas equipes.';f.questions[2].text='A liderança comunica prioridades e acompanha resultados.';state.forms.push(f);formId=f.id;}const s={id:uid('survey'),companyId:c.id,formId,title:fd.surveyTitle,description:fd.surveyDescription,status:'active',startsAt:new Date(`${fd.startsAt}T00:00:00`).toISOString(),expiresAt:new Date(`${fd.expiresAt}T23:59:59`).toISOString(),requireIdentification:true,lgpdRequired:!!fd.lgpdRequired,allowRepeat:!!fd.allowRepeat,showResult:!!fd.showResult,anonymous:false,token:secureToken(),createdAt:nowIso(),updatedAt:nowIso()};state.surveys.push(s);audit('Wizard de primeira pesquisa concluído','pesquisa',s.id,s.title);save();closeModal();openBulkInvite(s.id,state.users.filter(u=>u.companyId===c.id&&u.status!=='inactive'&&u.email&&u.receivesEmail!==false).map(u=>u.id));toast('Sua primeira pesquisa foi criada. Revise e envie os convites.','success');}

